INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym jest programowanie obiektowe i jakie są jego filary?', 'OOP opiera się na czterech filarach: enkapsulacji (ukrywanie szczegółów implementacji), dziedziczeniu (tworzenie hierarchii klas), polimorfizmie (różne zachowanie pod wspólnym interfejsem) i abstrakcji (modelowanie istotnych cech). W praktyce pozwala to pisać kod modularny i łatwiejszy do utrzymania.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij zasady SOLID.', 'SOLID to pięć zasad: S — klasa ma jeden powód do zmiany, O — otwarta na rozszerzenia, zamknięta na modyfikacje, L — podtyp musi być wymienialny z typem bazowym, I — wiele małych interfejsów zamiast jednego dużego, D — zależność od abstrakcji, nie konkretów. Stosowanie SOLID redukuje coupling i ułatwia testowanie.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się klasa abstrakcyjna od interfejsu?', 'Klasa abstrakcyjna może mieć implementację metod i stan (pola), interfejs definiuje tylko kontrakt (sygnatury metod). Klasa może implementować wiele interfejsów, ale dziedziczyć po jednej klasie abstrakcyjnej. Interfejsy promują luźne powiązanie — używaj ich, gdy chcesz zdefiniować zachowanie bez narzucania hierarchii.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz metody HTTP i kiedy je stosujesz?', 'GET — pobieranie zasobów, POST — tworzenie nowych, PUT — pełna aktualizacja, PATCH — częściowa aktualizacja, DELETE — usuwanie. GET i PUT są idempotentne (wielokrotne wywołanie daje ten sam efekt). POST nie jest idempotentny. HEAD zwraca tylko nagłówki, OPTIONS informuje o dostępnych metodach.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest REST API i jakie są jego zasady?', 'REST to styl architektoniczny oparty na zasobach identyfikowanych przez URI. Kluczowe zasady: bezstanowość (serwer nie przechowuje sesji), jednolity interfejs, klient-serwer, cache''owalność odpowiedzi i system warstwowy. Dobrze zaprojektowane REST API używa odpowiednich kodów HTTP i jest intuicyjne w nawigacji.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się REST od GraphQL?', 'REST zwraca ustaloną strukturę danych per endpoint, GraphQL pozwala klientowi określić dokładnie jakie pola potrzebuje w jednym zapytaniu. GraphQL eliminuje over-fetching i under-fetching, ale jest bardziej złożony w implementacji. REST jest prostszy, lepiej cache''owalny i lepiej wspierany przez infrastrukturę (CDN, proxy).', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Git i po co się go używa?', 'Git to rozproszony system kontroli wersji. Śledzi historię zmian, umożliwia równoległą pracę wielu osób (branching), cofanie błędów i przeglądanie historii. Każdy developer ma pełną kopię repozytorium. Kluczowe komendy to commit, push, pull, branch, merge. Jest fundamentem współczesnego workflow developmentu.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest merge conflict i jak go rozwiązujesz?', 'Merge conflict powstaje, gdy dwie gałęzie modyfikują te same linie pliku. Git oznacza konflikty znacznikami <<<<<<<, =======, >>>>>>>. Rozwiązuję je ręcznie analizując obie zmiany, wybieram poprawną wersję lub łączę obie, a następnie commituję. Używam też narzędzi jak VS Code diff editor do wizualnego porównania.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są testy jednostkowe i dlaczego są ważne?', 'Testy jednostkowe weryfikują izolowane fragmenty kodu (funkcje, metody) niezależnie od zależności zewnętrznych. Dają szybki feedback, dokumentują oczekiwane zachowanie i pozwalają bezpiecznie refaktoryzować. Dobrze napisany test ma fazę arrange (przygotowanie), act (wykonanie) i assert (weryfikacja). Powinny być szybkie i deterministyczne.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różnią się testy jednostkowe od integracyjnych i e2e?', 'Jednostkowe testują izolowane fragmenty (mockując zależności), integracyjne sprawdzają współpracę kilku modułów (np. serwis + baza), e2e testują cały flow z perspektywy użytkownika (np. Cypress/Playwright). Piramida testów mówi: dużo jednostkowych, mniej integracyjnych, najmniej e2e. Im wyżej, tym wolniejsze, ale bardziej realistyczne.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co oznaczają zasady DRY i KISS?', 'DRY (Don''t Repeat Yourself) — unikaj duplikacji logiki, wydzielaj wspólny kod do funkcji/modułów. KISS (Keep It Simple, Stupid) — preferuj proste rozwiązania nad złożone. Czasem DRY i KISS stoją w sprzeczności: nie abstrahuj na siłę tylko dlatego, że kod wygląda podobnie — premature abstraction jest tak samo szkodliwa jak duplikacja.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest SQL i czym różni się od NoSQL?', 'SQL to relacyjne bazy danych ze schematem (tabele, relacje, zapytania SQL) — np. PostgreSQL, MySQL. NoSQL to rodzina baz bez sztywnego schematu: dokumentowe (MongoDB), klucz-wartość (Redis), kolumnowe (Cassandra), grafowe (Neo4j). SQL daje ACID i spójność, NoSQL skalowalność horyzontalną i elastyczność schematu.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest programowanie asynchroniczne?', 'Programowanie asynchroniczne pozwala wykonywać operacje (I/O, HTTP) bez blokowania głównego wątku. W JS/TS używamy Promise i async/await. Callback był starszym podejściem, ale prowadził do „callback hell". Event loop w JS kolejkuje asynchroniczne operacje i wykonuje je, gdy stos wywołań jest pusty.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Promise w JavaScript?', 'Promise to obiekt reprezentujący wynik operacji asynchronicznej, która może być pending, fulfilled (resolved) lub rejected. Łańcuchujemy je metodami .then() i .catch(). Async/await to syntactic sugar nad Promises — czytelniejszy kod. Promise.all() uruchamia równolegle, Promise.allSettled() czeka na wszystkie niezależnie od wyniku.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak debugujesz problemy w aplikacji?', 'Zaczynam od reprodukcji problemu, analizuję logi i komunikaty błędów. Używam breakpointów w debuggerze (Chrome DevTools, IDE debugger) do śledzenia przepływu. Sprawdzam Network tab dla problemów z API, Console dla błędów JS. Stosuję też rubber duck debugging i dzielę problem na mniejsze części. Git bisect pomaga znaleźć commit wprowadzający bug.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Agile i Scrum?', 'Agile to filozofia iteracyjnego wytwarzania oprogramowania — krótkie cykle, ciągły feedback, adaptacja do zmian. Scrum to framework Agile z rolami (Product Owner, Scrum Master, Dev Team), ceremoniami (sprint planning, daily, review, retro) i artefaktami (backlog, sprint backlog). Sprinty trwają 1-4 tygodnie.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest code review i po co się go robi?', 'Code review to przegląd kodu przez innego programistę przed mergem. Łapie błędy, poprawia jakość, upowszechnia wiedzę w zespole i wymusza spójność stylu. Dobry review skupia się na logice, edge case''ach, bezpieczeństwie i czytelności — nie na stylu (od tego jest linter). Staram się dawać konstruktywny feedback z uzasadnieniem.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest CI/CD?', 'CI (Continuous Integration) to automatyczne budowanie i testowanie kodu po każdym pushu. CD (Continuous Delivery/Deployment) to automatyczne wdrażanie na środowiska. Pipeline CI/CD typowo obejmuje: build, lint, testy jednostkowe, testy integracyjne, deploy na staging, deploy na produkcję. Narzędzia: GitHub Actions, GitLab CI, Jenkins.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz podstawy bezpieczeństwa aplikacji webowych?', 'Najczęstsze zagrożenia (OWASP Top 10): XSS (wstrzyknięcie skryptów — waliduj input, escapuj output), SQL Injection (parametryzuj zapytania), CSRF (tokeny), broken authentication. Zawsze: HTTPS, hashuj hasła (bcrypt), waliduj dane po stronie serwera, stosuj zasadę least privilege, aktualizuj zależności.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest XSS i jak się przed nim chronić?', 'XSS (Cross-Site Scripting) to atak polegający na wstrzyknięciu złośliwego JavaScript do strony. Wyróżniamy Stored (zapisany w bazie), Reflected (w URL) i DOM-based. Ochrona: escapowanie outputu HTML, Content Security Policy (CSP), używanie frameworków które automatycznie sanityzują (Angular, React). Nigdy nie używaj innerHTML z danymi użytkownika.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest SQL Injection?', 'SQL Injection to atak, w którym atakujący wstrzykuje złośliwy SQL przez dane wejściowe (np. formularz logowania). Zapobieganie: parametryzowane zapytania (prepared statements), ORM, walidacja danych wejściowych, zasada least privilege dla konta bazodanowego. Nigdy nie buduj zapytań SQL przez konkatenację stringów z danymi użytkownika.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest HTTP i HTTPS?', 'HTTP to protokół komunikacji klient-serwer w modelu request-response. HTTPS dodaje szyfrowanie TLS/SSL — dane są zaszyfrowane w tranzycie, serwer jest uwierzytelniony certyfikatem. HTTPS jest wymagany dla nowoczesnych API przeglądarki (geolokacja, service workers) i wpływa na SEO. Certyfikaty można uzyskać za darmo z Let''s Encrypt.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest DOM?', 'DOM (Document Object Model) to drzewiasta reprezentacja dokumentu HTML w pamięci przeglądarki. JavaScript manipuluje DOM-em, aby dynamicznie zmieniać treść strony. Bezpośrednia manipulacja DOM jest kosztowna — dlatego frameworki (React, Angular) używają Virtual DOM lub change detection, aby minimalizować operacje na prawdziwym DOM.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest event loop w JavaScript?', 'Event loop to mechanizm, który pozwala single-threaded JS obsługiwać asynchroniczność. Callstack wykonuje synchroniczny kod, Web APIs (setTimeout, fetch) delegują operacje, callback queue (macrotasks) i microtask queue (Promises) czekają na pusty stack. Microtaski mają priorytet nad macrotaskami. To dlatego Promise.resolve() wykona się przed setTimeout(0).', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest closure w JavaScript?', 'Closure to funkcja, która „pamięta" zmienne z zakresu, w którym została utworzona, nawet po zakończeniu tego zakresu. Powstaje automatycznie, gdy funkcja wewnętrzna odwołuje się do zmiennych funkcji zewnętrznej. Zastosowania: enkapsulacja stanu, fabryki funkcji, moduły. Uwaga na closures w pętlach — var vs let ma znaczenie.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między var, let i const?', 'var ma function scope i jest hoistowany (podnoszony z wartością undefined). let i const mają block scope i temporal dead zone (błąd przy dostępie przed deklaracją). const wymaga inicjalizacji i nie pozwala na reassignment, ale obiekty przypisane do const mogą być mutowane. Zawsze używaj const, let tylko gdy musisz reassignować.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest hoisting?', 'Hoisting to mechanizm JS, w którym deklaracje zmiennych i funkcji są „przenoszone" na górę ich zakresu przed wykonaniem kodu. Deklaracje var są hoistowane z wartością undefined. Deklaracje function są hoistowane w całości (można wywołać przed deklaracją). let/const są hoistowane, ale w temporal dead zone — dostęp przed deklaracją rzuca ReferenceError.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest this w JavaScript?', 'this zależy od kontekstu wywołania: w metodzie obiektu — referencja do obiektu, w funkcji zwykłej — window (strict mode: undefined), w arrow function — dziedziczy this z zakresu nadrzędnego. Metody bind/call/apply pozwalają jawnie ustawić this. W klasach this wskazuje instancję. Arrow functions rozwiązują problem zagubionego this w callbackach.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się == od === w JavaScript?', '== (loose equality) wykonuje koercję typów przed porównaniem: "1" == 1 to true, null == undefined to true. === (strict equality) porównuje wartość i typ bez konwersji: "1" === 1 to false. Zawsze używaj === aby uniknąć nieintuicyjnych wyników koercji. Jedyny wyjątek: x == null sprawdza jednocześnie null i undefined.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest responsive web design?', 'RWD to podejście, w którym strona dostosowuje układ do rozmiaru ekranu. Narzędzia: media queries, flexbox, CSS Grid, relatywne jednostki (rem, %, vw/vh). Podejście mobile-first (styl bazowy dla mobile, media queries dla większych ekranów) jest preferowane. Viewport meta tag jest konieczny. Testuj na różnych urządzeniach i rozdzielczościach.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest box model w CSS?', 'Box model opisuje, jak przeglądarka renderuje elementy: content (treść), padding (wewnętrzny odstęp), border (obramowanie), margin (zewnętrzny odstęp). Domyślnie width dotyczy content-box — padding i border dodają się do szerokości. box-sizing: border-box sprawia, że width obejmuje padding i border, co jest zdecydowanie wygodniejsze.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest flexbox i kiedy go używasz?', 'Flexbox to jednowymiarowy system layoutu CSS (wiersze LUB kolumny). Kluczowe właściwości: display: flex, flex-direction, justify-content (oś główna), align-items (oś poprzeczna), flex-wrap, gap. Świetny do nawigacji, centrownia elementów, rozkładu kart. Dla dwuwymiarowych layoutów (wiersze I kolumny jednocześnie) lepszy jest CSS Grid.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest API i jak z niego korzystasz?', 'API (Application Programming Interface) to zdefiniowany interfejs komunikacji między systemami. W kontekście webowym najczęściej REST API lub GraphQL — klient wysyła HTTP request, serwer zwraca dane (JSON). Korzystam przez fetch/axios, obsługuję odpowiedzi i błędy. Dokumentacja (Swagger/OpenAPI) opisuje dostępne endpointy i formaty.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest JSON i do czego służy?', 'JSON (JavaScript Object Notation) to lekki format wymiany danych, czytelny dla ludzi i łatwy do parsowania przez maszyny. Obsługuje typy: string, number, boolean, null, object, array. Jest standardem w REST API. W JS: JSON.parse() konwertuje string na obiekt, JSON.stringify() — obiekt na string. Nie obsługuje komentarzy, funkcji ani undefined.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest npm/yarn i po co się go używa?', 'npm i yarn to package managery dla Node.js — zarządzają zależnościami projektu. package.json definiuje zależności i skrypty, node_modules przechowuje zainstalowane paczki, lock file (package-lock.json / yarn.lock) zapewnia powtarzalne buildy. Komendy: install, add, remove, update, audit (bezpieczeństwo). Nigdy nie commituj node_modules.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest TypeScript i dlaczego warto go używać?', 'TypeScript to nadzbiór JavaScript dodający statyczne typowanie. Łapie błędy w compile-time zamiast runtime, zapewnia lepsze autocomplete i refactoring w IDE, dokumentuje kod przez typy. Kompiluje się do JS. Kluczowe cechy: interfejsy, generics, enums, union types. Jest standardem w dużych projektach (Angular wymaga TS, React/Vue mocno go wspierają).', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest SPA (Single Page Application)?', 'SPA to aplikacja webowa ładująca jedną stronę HTML, a następnie dynamicznie aktualizująca treść przez JavaScript (bez przeładowania). Routing odbywa się po stronie klienta. Zalety: płynne UX, szybka nawigacja. Wady: wolniejszy initial load, problemy z SEO (rozwiązanie: SSR/SSG). Frameworki: Angular, React, Vue.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest wzorzec MVC?', 'MVC (Model-View-Controller) to wzorzec architektoniczny dzielący aplikację na trzy warstwy: Model (dane i logika biznesowa), View (prezentacja), Controller (obsługa requestów i koordynacja). Separacja ułatwia testowanie i rozwój. Warianty: MVVM (Angular), MVP. W praktyce frameworki frontendowe używają komponentów, które łączą View i Controller.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest dependency injection?', 'DI to wzorzec, w którym zależności obiektu są dostarczane z zewnątrz zamiast tworzone wewnątrz. Umożliwia luźne powiązanie, łatwiejsze testowanie (podmiana na mocki) i konfigurowalność. W Angular DI jest wbudowane — serwisy rejestruje się w providerach, a framework wstrzykuje je przez konstruktor lub inject(). W testach łatwo podmienić na fake.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest middleware?', 'Middleware to warstwa pośrednia przetwarzająca request/response w pipeline. W Express.js to funkcja (req, res, next) — może logować, autoryzować, parsować body, obsługiwać błędy. Middleware wykonuje się sekwencyjnie, next() przekazuje do następnego. Przykłady: cors(), body-parser, sprawdzanie tokenu JWT, rate limiting.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz kody statusu HTTP?', '2xx — sukces: 200 OK, 201 Created, 204 No Content. 3xx — przekierowania: 301 Moved Permanently, 304 Not Modified. 4xx — błąd klienta: 400 Bad Request, 401 Unauthorized (brak uwierzytelnienia), 403 Forbidden (brak uprawnień), 404 Not Found, 409 Conflict, 422 Unprocessable Entity. 5xx — błąd serwera: 500, 502, 503.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest CORS?', 'CORS (Cross-Origin Resource Sharing) to mechanizm bezpieczeństwa przeglądarki blokujący żądania do innej domeny. Serwer musi odpowiedzieć nagłówkami Access-Control-Allow-Origin, Allow-Methods, Allow-Headers. Preflight request (OPTIONS) jest wysyłany przed zapytaniami z custom headers. Na developmencie rozwiązuję proxy w webpack/angular.json.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest localStorage, sessionStorage i cookies?', 'localStorage — dane trwałe w przeglądarce (do 5-10MB), dostępne po odświeżeniu i zamknięciu. sessionStorage — dane na czas sesji karty. Cookies — małe dane (4KB) wysyłane automatycznie z każdym HTTP request, mają expiry, path, domain, flagi Secure/HttpOnly. Do tokenów JWT preferuję httpOnly cookies (bezpieczniejsze niż localStorage — odporne na XSS).', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Docker?', 'Docker to platforma konteneryzacji — pakuje aplikację ze wszystkimi zależnościami w lekki, przenośny kontener. Dockerfile definiuje instrukcje budowania obrazu. Kontener jest izolowanym procesem dzielącym kernel hosta. Zalety: „works on my machine" znika, spójne środowiska dev/staging/prod, szybki deploy. Docker Compose orkiestruje wiele kontenerów.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest token JWT i jak działa?', 'JWT (JSON Web Token) to standard tokenów składający się z trzech części: header (algorytm), payload (dane/claims) i signature (podpis). Serwer generuje JWT po logowaniu, klient wysyła go w nagłówku Authorization: Bearer <token>. Serwer weryfikuje podpis bez bazy — token jest self-contained. Uwaga: payload jest tylko base64, nie szyfrowany.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest ORM i po co się go używa?', 'ORM (Object-Relational Mapping) mapuje tabele bazy na obiekty w kodzie — zamiast pisać SQL, operujesz na obiektach. Przykłady: Prisma, TypeORM, Sequelize, Hibernate. Zalety: bezpieczeństwo (ochrona przed SQL injection), produktywność, migracje schematu. Wady: N+1 problem, mniejsza kontrola nad zapytaniami — czasem trzeba wrócić do raw SQL.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest garbage collection?', 'Garbage collection (GC) to automatyczne zarządzanie pamięcią — zwalnia obiekty, do których nie ma referencji. W JS/Java/C# nie musisz ręcznie alokować/zwalniać pamięci. GC w V8 (JS) używa algorytmu mark-and-sweep. Memory leak powstaje, gdy obiekt jest niepotrzebny, ale wciąż ma referencję (np. event listener, closure, timer nie wyczyszczony).', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa prototypowe dziedziczenie w JavaScript?', 'Każdy obiekt JS ma ukryty link [[Prototype]] do innego obiektu. Gdy JS szuka właściwości, idzie w górę łańcucha prototypów. Object.create() tworzy obiekt z danym prototypem. Klasy ES6 to syntactic sugar nad prototypami. __proto__ to getter/setter, Object.getPrototypeOf() jest preferowany. Modyfikowanie wbudowanych prototypów jest antywzorcem.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest array destructuring i spread operator?', 'Destructuring to skrócony zapis wyciągania wartości: const [a, b] = [1, 2]; const {name} = obj. Spread (...) „rozpakowuje" iterable: [...arr1, ...arr2] łączy tablice, {...obj, key: val} tworzy nowy obiekt z nadpisanymi polami. Rest parameter (...args) zbiera argumenty do tablicy. Oba są niezbędne w codziennej pracy z JS/TS.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są higher-order functions?', 'Higher-order function to funkcja przyjmująca inną funkcję jako argument lub zwracająca funkcję. Przykłady wbudowane: map, filter, reduce, forEach, sort. Umożliwiają programowanie deklaratywne i kompozycję. Np. arr.filter(x => x > 0).map(x => x * 2) jest czytelniejsze niż pętla for z warunkiem. Reduce jest najpotężniejszy — można nim zaimplementować map i filter.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest immutability i dlaczego jest ważna?', 'Niemutowalność to zasada, w której obiekt po utworzeniu nie jest modyfikowany — tworzy się nową kopię ze zmianami. Zapobiega side-effectom, ułatwia debugowanie i śledzenie zmian (np. Redux, NgRx). W JS: Object.freeze() (płytki), spread operator i map/filter (tworzą nowe tablice). Biblioteki: Immer (JS), readonly w TypeScript.', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa async/await?', 'async/await to syntactic sugar nad Promises. Funkcja oznaczona async zawsze zwraca Promise. await wstrzymuje wykonanie do rozwiązania Promise. Obsługa błędów: try/catch zamiast .catch(). Uwaga: await w pętli for wykonuje sekwencyjnie — do równoległego użyj Promise.all(). Top-level await działa w ES modules.', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest webpack/vite i po co się go używa?', 'Webpack i Vite to bundlery — pakują moduły JS, CSS, assety w zoptymalizowane pliki do przeglądarki. Webpack jest konfigurowalne (loadery, pluginy), Vite jest szybszy (ESM w dev, Rollup w build). Funkcje: tree-shaking (usuwanie nieużywanego kodu), code splitting (lazy loading), hot module replacement (HMR) — zmiany bez przeładowania.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest semantic HTML?', 'Semantic HTML to używanie elementów o znaczeniu (header, nav, main, article, section, footer) zamiast generycznych div i span. Poprawia dostępność (screen readery interpretują strukturę), SEO (wyszukiwarki lepiej rozumieją treść) i czytelność kodu. Button zamiast div z onClick, label z for, odpowiednie nagłówki h1-h6.', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest accessibility (a11y)?', 'Dostępność to projektowanie aplikacji użytecznych dla osób z niepełnosprawnościami. Kluczowe praktyki: semantic HTML, atrybuty ARIA, nawigacja klawiaturą (tabindex, focus management), kontrast kolorów (WCAG 2.1), alt na obrazach, labels na formularzach. Testuję narzędziami: Lighthouse, axe DevTools. Dostępność jest też wymogiem prawnym (EU: EAA).', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między null a undefined w JS?', 'undefined oznacza, że zmienna została zadeklarowana, ale nie przypisano jej wartości — to domyślna wartość. null to jawne przypisanie „brak wartości" przez programistę. typeof undefined === "undefined", typeof null === "object" (historyczny bug). W praktyce: null używam, gdy chcę jawnie oznaczyć brak, undefined jest wynikiem braku inicjalizacji.', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są design patterns i jakie znasz?', 'Design patterns to sprawdzone rozwiązania powtarzalnych problemów projektowych. Kreacyjne: Singleton (jedna instancja), Factory (tworzenie obiektów), Builder. Strukturalne: Adapter, Decorator, Facade. Behawioralne: Observer (pub/sub), Strategy, Iterator. W codziennej pracy najczęściej spotykam Observer (RxJS), Singleton (Angular services), Factory i Strategy.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest refactoring?', 'Refactoring to zmiana wewnętrznej struktury kodu bez zmiany zewnętrznego zachowania. Cele: poprawa czytelności, redukcja duplikacji, uproszczenie logiki. Wymaga dobrych testów (safety net). Typowe techniki: extract method/function, rename, inline, introduce parameter object. Refaktoryzuję małymi krokami, uruchamiając testy po każdej zmianie.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest PWA (Progressive Web App)?', 'PWA to aplikacja webowa z cechami natywnej: działa offline (Service Worker + Cache API), instalowalna na urządzeniu (manifest.json), obsługuje push notyfikacje. Service Worker to proxy między przeglądarką a siecią — przechwytuje requesty i serwuje z cache. PWA musi działać na HTTPS. Strategie cache: cache-first, network-first, stale-while-revalidate.', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak wygląda Twój typowy dzień pracy jako developer?', 'Zaczynam od daily standup — co zrobiłem, co planuję, jakie blokery. Pobieram zadania z backlogu (Jira/Linear), piszę kod na feature branchu z testami, tworzę PR i proszę o code review. Poprawiam uwagi, po akceptacji merge do main. Uczestniczę w refinement i planning. Automatyczne CI/CD wdraża zmiany. Poświęcam też czas na naukę i pair programming.', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Jak zaprojektowałbyś system skracania URL-i (np. bit.ly)?', 'Potrzebuję: serwis generujący unikalny krótki klucz (base62 z auto-increment ID lub hash), baza klucz-URL (Redis dla szybkości + persistent store), redirect 301/302. Skalowalność: load balancer, sharding bazy po kluczu, CDN. Cache popular URLs. Rozważenia: rate limiting, analytics (zliczanie kliknięć), TTL na linki, collision handling.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mikroserwisy vs monolit — kiedy co wybrać?', 'Monolit na start: prostszy deploy, łatwiejsze debugowanie, jeden repo. Mikroserwisy gdy: zespół rośnie (autonomia), różne komponenty skalują się niezależnie, potrzeba różnych technologii. Mikroserwisy dodają złożoność: distributed transactions, eventual consistency, service discovery, observability. Zacznij od modularnego monolitu i wydzielaj serwisy, gdy jest jasna potrzeba.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij twierdzenie CAP.', 'CAP mówi, że rozproszony system może gwarantować tylko dwa z trzech: Consistency (każdy odczyt widzi najnowszy zapis), Availability (każdy request dostaje odpowiedź), Partition tolerance (system działa mimo utraty komunikacji). W praktyce partycje się zdarzają, więc wybierasz CP (np. ZooKeeper) lub AP (np. Cassandra). PACELC rozszerza: nawet bez partycji — latency vs consistency.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest event-driven architecture?', 'EDA to architektura, w której komponenty komunikują się przez zdarzenia (events) zamiast bezpośrednich wywołań. Producent emituje event, broker (Kafka, RabbitMQ) go dystrybuuje, konsumenci reagują. Zalety: luźne powiązanie, skalowalność, odporność. Wyzwania: eventual consistency, ordering, idempotency, debugging flow rozproszonych zdarzeń.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest CQRS i kiedy go stosować?', 'CQRS (Command Query Responsibility Segregation) rozdziela model odczytu od zapisu. Komendy (write) modyfikują stan, zapytania (read) go pobierają — z osobnymi modelami/bazami. Stosuj, gdy: read i write mają różne wymagania skalowania, potrzebujesz zdenormalizowanych widoków, system jest event-driven. Często łączony z Event Sourcing. Dodaje złożoność — nie stosuj „bo można".', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak optymalizujesz wolne zapytanie SQL?', 'Zaczynam od EXPLAIN ANALYZE — patrzę na seq scan vs index scan, koszt, liczbę wierszy. Dodaję brakujące indeksy (na kolumnach WHERE, JOIN, ORDER BY). Sprawdzam: N+1 problem, brak LIMIT, niepotrzebne SELECT *, złe JOINy. Rozważam: composite index, partial index, materialized view. Monitoruję pg_stat_statements. Denormalizacja jako ostateczność.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz strategie cache''owania?', 'Cache-aside (lazy): aplikacja najpierw sprawdza cache, przy miss pobiera z bazy i zapisuje. Write-through: zapis jednocześnie do cache i bazy. Write-behind: zapis do cache, asynchronicznie do bazy. TTL zapobiega stale data. Invalidation: time-based, event-based. Narzędzia: Redis, Memcached. Cachuj na wielu warstwach: CDN, reverse proxy, aplikacja, baza.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest message queue i kiedy jej używasz?', 'Message queue (RabbitMQ, SQS, Kafka) to pośrednik asynchronicznej komunikacji. Producent wysyła wiadomość, konsument przetwarza. Zastosowania: odciążenie ciężkich operacji (email, generowanie PDF), decoupling serwisów, load leveling, retry logic. Kafka dodatkowo zapewnia log-based streaming z retencją. Ważne: idempotentny consumer, dead letter queue dla błędów.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa load balancing?', 'Load balancer rozdziela ruch między wiele instancji serwera. Algorytmy: round-robin, least connections, IP hash, weighted. L4 (transport — TCP) vs L7 (application — HTTP, routing po URL/header). Health checks wykrywają martwe instancje. Narzędzia: Nginx, HAProxy, AWS ALB. Session affinity (sticky sessions) dla stateful apps, ale preferuj stateless z shared session store.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest containerization i jaka jest różnica między kontenerem a VM?', 'Kontener to izolowany proces dzielący kernel hosta — lekki, szybki start (ms), mały rozmiar. VM to pełny system operacyjny z hypervisorem — cięższy, ale pełna izolacja. Docker używa namespaces i cgroups Linuxa. Kontenery idealnie pasują do mikroserwisów: immutable infrastructure, szybki deploy, łatwe skalowanie. Kubernetes orkiestruje kontenery w produkcji.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest observability i czym różni się od monitoringu?', 'Monitoring to zbieranie predefiniowanych metryk (CPU, pamięć, czas odpowiedzi) i alertowanie na thresholds. Observability to zdolność zrozumienia stanu systemu na podstawie jego outputów — trzy filary: logs (zdarzenia), metrics (liczby agregowane), traces (przepływ requestu między serwisami). Narzędzia: Prometheus+Grafana, ELK, Jaeger/Zipkin. Structured logging jest kluczowy.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz technical debt?', 'Tech debt to kompromisy w jakości kodu przyspieszające dostarczanie, ale spowalniające przyszły rozwój. Zarządzam: identyfikuję i dokumentuję (ADR), priorytetyzuję według wpływu na velocity, alokuję % sprintu na spłatę (np. 20%). Nie każdy dług jest zły — świadomy dług z planem spłaty jest OK. Refactoring ciągły jest lepszy niż wielkie przepisywanie.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak mentorujesz juniorów?', 'Zaczynam od zrozumienia ich poziomu i celów. Daję zadania stopniowo trudniejsze z jasnym kontekstem „dlaczego". Code review traktuję jako narzędzie nauki — wyjaśniam, nie tylko wskazuję. Pair programming na trudniejszych zadaniach. Zachęcam do zadawania pytań i samodzielnego rozwiązywania (dając wskazówki, nie gotowe rozwiązania). Regularne 1:1 i feedback.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak podejmujesz decyzje architektoniczne?', 'Zaczynam od zrozumienia wymagań (funkcjonalnych i niefunkcjonalnych: skala, latency, budżet). Analizuję opcje z tradeoffami. Dokumentuję w ADR (Architecture Decision Record): kontekst, rozważane opcje, decyzja, konsekwencje. Konsultuję z zespołem. Preferuję proste rozwiązania, reversible decisions i evolutionary architecture. YAGNI — nie projektuj na zapas.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Event Sourcing?', 'Event Sourcing przechowuje sekwencję zdarzeń (events) zamiast aktualnego stanu. Stan odtwarzasz przez replay eventów. Zalety: pełna historia zmian, audit log, możliwość projekcji różnych widoków, temporal queries. Wyzwania: event versioning, event schema evolution, wydajność odtwarzania (rozwiązanie: snapshots). Często łączony z CQRS.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak skanujesz horyzontalnie bazę danych?', 'Sharding: dzielisz dane między wiele instancji po kluczu (np. user_id mod N). Wybór shard key jest krytyczny — musi równomiernie rozkładać dane. Wyzwania: cross-shard queries, rebalancing, distributed transactions. Alternatywy: read replicas (skalowanie odczytów), partitioning (w jednej instancji). Managed sharding: CockroachDB, Vitess, Citus. Skaluj pionowo, dopóki się da.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest distributed transaction i jak ją obsłużyć?', 'Transakcja rozproszona obejmuje wiele serwisów/baz. Two-phase commit (2PC): koordynator pyta o gotowość, potem commituje — wolny, blokujący. Saga pattern: sekwencja lokalnych transakcji z kompensacjami przy błędzie (choreography lub orchestration). W mikroserwisach preferuj Saga z eventual consistency. Idempotentne handlery są kluczowe.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektowałbyś system notyfikacji?', 'Komponenty: API przyjmujący event, router decydujący o kanale (email, push, SMS, in-app), queue per kanał, providerzy (SendGrid, FCM, Twilio), baza preferencji użytkownika. Ważne: rate limiting, deduplication, retry z exponential backoff, dead letter queue, template engine, tracking (delivered/read). Skalowanie: osobne consumers per kanał, priority queue.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest API Gateway?', 'API Gateway to single entry point dla klientów w architekturze mikroserwisowej. Funkcje: routing, autentykacja, rate limiting, load balancing, request/response transformation, circuit breaker, caching, logging. Narzędzia: Kong, AWS API Gateway, Nginx. BFF (Backend for Frontend) to wariant — osobny gateway per typ klienta (mobile, web).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest circuit breaker pattern?', 'Circuit breaker chroni system przed kaskadowymi awariami. Stany: Closed (normal flow), Open (blokuje requesty po przekroczeniu progu błędów, zwraca fallback), Half-Open (próbuje po timeout). Implementacja: Hystrix (legacy), Resilience4j, Polly (.NET). Kluczowe: sensowne thresholds, fallback response, monitoring stanu circuit breakerów.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak podchodzisz do migracji legacy systemu?', 'Strangler Fig Pattern: stopniowo zastępuję fragmenty legacy nowym kodem, routując ruch przez proxy. Nie big bang rewrite (ryzyko!). Kroki: zrozum obecny system (dokumentacja, testy characterization), zidentyfikuj granice, wydzielaj bounded contexts. Parallel run: nowy i stary działają równocześnie, porównuję wyniki. Feature flags do kontrolowanego przełączania.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest twelve-factor app?', 'Twelve-factor to metodologia budowania SaaS. Kluczowe czynniki: codebase w VCS, dependencies jawnie deklarowane, config w env variables, backing services jako attached resources, build/release/run oddzielone, stateless processes, port binding, concurrency przez procesy, disposability (szybki start/stop), dev/prod parity, logs jako event stream, admin tasks jako one-off.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zapewnić wysoką dostępność systemu?', 'Redundancja: multiple instances, multi-AZ/region. Eliminacja SPOF (single point of failure). Load balancing z health checks. Database: primary-replica z automatic failover. Graceful degradation (fallbacki, feature flags). Chaos engineering (testuj awarie). SLA/SLO definiują target. Blue-green deploy eliminuje downtime. Circuit breakery chronią przed cascading failures.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest DDD (Domain-Driven Design)?', 'DDD to podejście, w którym architektura odzwierciedla domenę biznesową. Kluczowe koncepty: ubiquitous language (wspólny język z biznesem), bounded contexts (granice modeli), aggregates (spójne grupy encji), entities (identyfikowane po ID), value objects (identyfikowane po wartości), domain events. Bounded contexts mapują się na mikroserwisy.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest idempotentność i dlaczego jest ważna w API?', 'Operacja idempotentna daje ten sam wynik niezależnie od liczby wywołań. GET, PUT, DELETE powinny być idempotentne. POST zazwyczaj nie jest. Ważna w distributed systems: retry nie powoduje duplikatów. Implementacja: idempotency key w nagłówku, sprawdzanie czy operacja już wykonana (deduplication). Krytyczna dla payment systems i message queues.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektujesz REST API dla dużego systemu?', 'Konwencje: pluralne rzeczowniki (/users/{id}), HTTP verbs odpowiednio, status codes, wersjonowanie (URL lub header). Paginacja: cursor-based (skalowalny) > offset. Filtrowanie: query params. Rate limiting (429). HATEOAS dla discoverability. Dokumentacja: OpenAPI/Swagger. Bulk operations. Idempotency keys. Consistent error format. Backwards compatibility.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest blue-green deployment?', 'Blue-green to strategia deploy, w której masz dwa identyczne środowiska: blue (aktualne) i green (nowe). Deploy na green, testuj, przełącz ruch. Rollback = przełączenie z powrotem na blue. Zalety: zero downtime, szybki rollback. Wady: podwójne zasoby, migracje bazy wymagają backward compatibility. Wariant: canary — kierujesz % ruchu na nową wersję stopniowo.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektowałbyś system rate limiting?', 'Algorytmy: token bucket (steady rate z burst), sliding window (precyzyjny), fixed window (prosty, ale edge case na granicy okna), leaky bucket. Implementacja: Redis (INCR + EXPIRE, lub sorted sets dla sliding window). Klucze: per user, per IP, per endpoint. Nagłówki: X-RateLimit-Limit, Remaining, Reset. 429 Too Many Requests + Retry-After header.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz graceful shutdown w aplikacji?', 'Przy SIGTERM: przestań przyjmować nowe requesty, dokończ in-flight requests (timeout), zamknij połączenia do bazy/cache, zwolnij zasoby, exit z kodem 0. W Kubernetes: preStop hook + terminationGracePeriodSeconds. Health check przechodzi na unhealthy, load balancer przestaje kierować ruch. Consumer: dokończ przetwarzanie bieżącej wiadomości, commituj offset.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest eventual consistency?', 'Eventual consistency to model, w którym system gwarantuje, że dane będą spójne „w końcu" (po pewnym czasie), ale nie natychmiast. Przeciwieństwo strong consistency. Typowe w systemach rozproszonych (AP z CAP). Przykład: po dodaniu komentarza inny user może go zobaczyć z opóźnieniem. Wymaga: idempotentne operacje, retry, conflict resolution, kompensacja.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektujesz system uwierzytelniania i autoryzacji?', 'Authentication (kim jesteś): OAuth2/OIDC z IdP (Keycloak, Auth0), JWT z refresh tokens, MFA. Authorization (co możesz): RBAC (role), ABAC (atrybuty), policy engine (OPA). JWT w httpOnly cookie. Access token krótki (15min), refresh token długi + rotation. Centralized auth service. Principle of least privilege. Audit log wszystkich zmian uprawnień.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest infrastructure as code?', 'IaC to zarządzanie infrastrukturą przez kod (deklaratywny) zamiast manualnych konfiguracji. Narzędzia: Terraform (multi-cloud, state file), Pulumi (real programming languages), CloudFormation (AWS), Ansible (configuration management). Zalety: wersjonowanie, powtarzalność, code review na infrastrukturę, disaster recovery. GitOps: infrastruktura driven przez Git.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak radzisz sobie z N+1 query problem?', 'N+1 to sytuacja, gdy pobierasz listę encji (1 query) i dla każdej z nich dopytywasz o relację (N queries). Rozwiązania: eager loading (JOIN/LEFT JOIN), batch loading (WHERE id IN(...)), dataloader pattern (batching + caching per request w GraphQL). W ORM: include/eager option. Wykrywanie: logowanie SQL, APM tools, testy liczby zapytań.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest feature flag i jak go używasz?', 'Feature flag to warunek w kodzie kontrolujący dostępność funkcjonalności bez deploy. Zastosowania: canary release (% userów), A/B testing, kill switch, trunk-based development (merge nieskończony feature). Narzędzia: LaunchDarkly, Unleash, Flagsmith. Ważne: cleanup starych flag, nie zagnieżdżaj wielu flag, testuj obie ścieżki. Technical debt jeśli nie usuwasz.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak monitorujesz wydajność aplikacji w produkcji?', 'APM (Application Performance Monitoring): Datadog, New Relic, Dynatrace — śledzą response time, throughput, error rate. RED metrics (Rate, Errors, Duration) dla serwisów, USE (Utilization, Saturation, Errors) dla zasobów. Distributed tracing (Jaeger) dla mikrousług. Alerting: PagerDuty/OpsGenie. Dashboardy w Grafana. SLI/SLO jako target. Real User Monitoring (RUM) dla frontendu.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest backpressure i jak go obsłużyć?', 'Backpressure to sytuacja, gdy producent generuje dane szybciej niż konsument może je przetworzyć. Bez obsługi: memory overflow, crash. Strategie: buforowanie (ograniczone), dropping (najstarsze lub losowe), throttling producenta, dynamiczne skalowanie konsumentów. W RxJS: switchMap, debounceTime. W Kafka: partycje + consumer groups. Queue z max size i back-off.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Service Mesh?', 'Service mesh to warstwa infrastruktury zarządzająca komunikacją między mikroserwisami. Sidecar proxy (np. Envoy) obsługuje: mTLS, load balancing, circuit breaking, retry, observability — bez zmian w kodzie aplikacji. Narzędzia: Istio, Linkerd. Control plane zarządza konfiguracją, data plane przetwarza ruch. Dodaje latency i złożoność — rozważ, czy potrzebujesz.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz konfiguracją w mikroserwisach?', 'Hierarchia: defaults w kodzie, environment variables (12-factor), config files per environment, centralized config service (Consul, Spring Cloud Config, AWS Parameter Store). Sekrety: Vault, AWS Secrets Manager — nigdy w kodzie/repo. Config hot-reload bez restartu. Feature flags dla runtime configuration. GitOps: config w repozytorium, sync automatyczny.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest database connection pooling?', 'Connection pool to zbiór wcześniej otwartych połączeń do bazy, reużywanych między requestami. Tworzenie połączenia jest kosztowne (TCP handshake, auth, SSL). Pool manager: PgBouncer (PostgreSQL), HikariCP (Java). Konfiguracja: min/max connections, idle timeout, max lifetime. Za mało — bottleneck, za dużo — baza przeciążona. Formuła: connections = (core_count * 2) + disk_spindles.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektowałbyś feed aktywności (np. Twitter)?', 'Dwa podejścia: fan-out on write (przy poście, wstaw do feed każdego followera — szybki odczyt, kosztowny zapis dla celebrytów) lub fan-out on read (przy odczycie, pobierz posty followowanych — wolniejszy odczyt, prostszy zapis). Hybrid: fan-out on write dla zwykłych, on read dla celebrytów. Cache timeline w Redis. Paginacja cursor-based. Ranking algorytm.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest optimistic vs pessimistic locking?', 'Optimistic: zakłada brak konfliktów, sprawdza wersję przy zapisie (version column). Jeśli wersja się zmieniła — retry. Dobry przy niskim contention. Pessimistic: blokuje rekord na czas edycji (SELECT FOR UPDATE). Gwarantuje brak konfliktów, ale zmniejsza throughput. Optimistic preferowany w web apps (request-response), pessimistic w krytycznych operacjach (finanse).', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest trunk-based development?', 'TBD to strategia, w której wszyscy commitują do main/trunk. Feature branche są krótkotrwałe (max 1-2 dni). Wymaga: CI, feature flags, pair programming, dobra test suite. Zalety: mniej merge conflictów, szybszy feedback, prostszy pipeline. Kontrastuje z Git Flow (długotrwałe branche develop, release). Google, Facebook, Netflix stosują TBD.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektujesz API backward compatible?', 'Zasady: dodawaj pola, nie usuwaj. Nowe pola opcjonalne z defaults. Wersjonowanie: URL (/v2/) lub header (Accept-Version). Deprecation policy: ogłoś, daj czas na migrację, monitoruj użycie starej wersji. Nie zmieniaj semantyki istniejących pól. Breaking change = nowa wersja. Consumer-driven contract testing (Pact) wykrywa niezgodności.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są SLI, SLO i SLA?', 'SLI (Service Level Indicator) to metryka: np. % requestów < 200ms. SLO (Service Level Objective) to cel wewnętrzny: np. 99.9% requestów < 200ms. SLA (Service Level Agreement) to kontrakt z klientem z konsekwencjami (kary, kredyty). Error budget = 100% - SLO — gdy się wyczerpie, stop nowych features, focus na reliability. Mierz to, co użytkownik odczuwa.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak radzisz sobie z distributed logging?', 'Structured logging (JSON) z correlation ID przekazywanym między serwisami (przez header). Centralized log aggregation: ELK Stack (Elasticsearch, Logstash, Kibana) lub Loki+Grafana. Log levels: error (wymaga akcji), warn (anomalia), info (flow), debug (troubleshooting). Nie loguj PII/secrets. Retention policy. Alerting na error patterns.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest chaos engineering?', 'Chaos engineering to praktyka celowego wprowadzania awarii w systemie produkcyjnym (lub staging) by zweryfikować odporność. Narzędzia: Chaos Monkey (Netflix), Gremlin, LitmusChaos. Eksperymenty: kill instancji, dodanie latency, partycja sieci, pełny dysk. Wymaga: hipoteza, blast radius limitation, monitoring. Buduje zaufanie do systemu i ujawnia ukryte zależności.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektowałbyś system kolejkowania zadań?', 'Komponenty: producer API, queue (Redis/SQS/RabbitMQ), consumer workers. Cechy: priority queues, delay/scheduled jobs, retry z exponential backoff, dead letter queue, job deduplication (idempotency key), rate limiting. Monitoring: queue depth, processing time, failure rate. Autoscaling workers na podstawie queue depth. Narzędzia: BullMQ (Node), Celery (Python), Sidekiq (Ruby).', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak testujesz mikroserwisy?', 'Piramida: unit testy (logika), integration testy (serwis + baza/queue), contract testy (Pact — zgodność API między serwisami), component testy (serwis z mockowanymi zależnościami), e2e testy (full flow, minimalizuj). Testcontainers dla real dependencies w CI. Consumer-driven contracts łapią breaking changes. Chaos testing w staging/prod.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest database migration i jak ją zarządzasz?', 'Migracje to wersjonowane zmiany schematu bazy w kodzie. Narzędzia: Flyway, Liquibase, Prisma Migrate, Knex, Django migrations. Zasady: additive changes (nie usuwaj kolumn od razu), backward compatible (stary kod musi działać z nowym schematem), ekspanduj-kontrakcja (dodaj nową, migruj dane, usuń starą). Rollback: oddzielna migracja, nie revert. Testuj migracje na kopii produkcji.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak komunikujesz się z nietechnicznymi stakeholderami?', 'Unikam żargonu technicznego, tłumaczę w kontekście biznesowym (wartość, ryzyko, czas, koszt). Używam analogii i wizualizacji. Przy decyzjach architektonicznych prezentuję opcje z tradeoffami. Transparentnie komunikuję ryzyka i blockers. Regularne statusy. RFC/ADR dokumentują decyzje. Słucham wymagań biznesowych i proponuję techniczne rozwiązania spełniające je.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest data partitioning i jakie są typy?', 'Partitioning dzieli duże tabele na mniejsze fragmenty. Typy: range (np. po dacie — miesiące), hash (równomierny rozkład po kluczu), list (po kategorii). Zalety: szybsze query (partition pruning), łatwiejsze archiwizowanie, parallel scan. PostgreSQL obsługuje declarative partitioning. Partycja vs sharding: partitioning w jednej bazie, sharding na wielu maszynach.', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak wdrażasz zero-downtime deployment?', 'Wymagania: rolling update (nowa wersja stopniowo zastępuje starą), backward-compatible migrations (expand-contract), health checks, graceful shutdown. Blue-green lub canary deployment. Database: additive schema changes, dual-write jeśli konieczne. Feature flags do stopniowego włączania. Kubernetes rolling update strategy z maxSurge i maxUnavailable.', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest bounded context w DDD?', 'Bounded context to granica, w której model domeny jest spójny i ma jednoznaczne definicje. Każdy kontekst ma swój ubiquitous language — „User" może znaczyć co innego w kontekście billing i auth. Konteksty komunikują się przez events lub API, nie współdzielą bazy. Mapują się naturalnie na mikroserwisy. Context mapping definiuje relacje: shared kernel, customer-supplier, conformist.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektowałbyś system wyszukiwania pełnotekstowego?', 'Elasticsearch (lub OpenSearch): inverted index, analyzers (tokenization, stemming, synonyms), relevance scoring (TF-IDF/BM25). Architektura: source of truth w primary DB, async sync do ES (CDC lub event). Typy queries: match, multi_match, bool, fuzzy. Pagination: search_after (nie offset). Sugestie: completion suggester. Facets: aggregations. Skalowanie: shards, replicas.', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest webhook i jak go poprawnie zaimplementować?', 'Webhook to HTTP callback — serwis A wysyła POST do URL serwisu B przy zdarzeniu. Implementacja: retry z exponential backoff, signature verification (HMAC), idempotency (deduplication po event ID), timeout i circuit breaker. Odbiorca: szybki ACK (202), przetwarzanie async w queue. Delivery guarantee: at-least-once. Dead letter dla nieosiągalnych endpointów.', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak podchodzisz do postmortem po incydencie?', 'Blameless postmortem po każdym poważnym incydencie. Struktura: timeline zdarzeń, impact, root cause (5 Whys), contributing factors, co zadziałało, co nie, action items z właścicielami i deadlinami. Cel: zapobiec powtórzeniu, nie karać ludzi. Dzielenie się wiedzą z zespołem. Śledź completion rate action items. Budowanie kultury uczenia się na błędach.', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest GraphQL Federation?', 'Federation pozwala wielu mikroserwsom udostępniać jeden spójny graf GraphQL. Każdy serwis definiuje swój subgraph (schema). Apollo Router/Gateway łączy je w supergraph. Dyrektywy @key, @shareable, @external definiują jak typy i pola są rozdzielone. Zalety: team autonomy, single endpoint dla klienta. Wyzwania: query planning, latency, distributed tracing.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz wersjami API w dużym systemie?', 'Strategie: URI versioning (/v1/users — najprostsze), header versioning (Accept: application/vnd.api+json;version=2), query param (?version=2). Preferuję URI dla public API. Sunset header informuje o deprecation. Monitoruj użycie starych wersji. API changelog. Minimum 2 wersje jednocześnie. Consumer-driven contract testy zapobiegają niezamierzonym zmianom.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektujesz system odporny na awarie (resilient)?', 'Wzorce: circuit breaker (fail fast), retry z jitter, timeout (nie czekaj w nieskończoność), bulkhead (izolacja zasobów), fallback (graceful degradation). Redundancja: multi-AZ, replicas. Health checks: liveness (restart) i readiness (ruch). Graceful shutdown. Chaos engineering do weryfikacji. Cel: system działa z degradacją, nie pada całkowicie.', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak oceniasz, czy microservice powinien zostać wydzielony?', 'Kryteria: niezależny cykl deploymentu (inny team/tempo zmian), różne wymagania skalowania, bounded context z jasną granicą, inna technologia potrzebna. Kontra: shared data model, tight coupling, potrzeba distributed transactions — zostawiaj razem. Zacznij od modularnego monolitu z jasnymi granicami modułów. Wydzielaj, gdy masz dowody potrzeby, nie „bo mikroserwisy są cool".', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym różni się type od interface w TypeScript?', 'Interface deklaruje kształt obiektu i może być rozszerzany (extends) oraz mergowany (declaration merging). Type alias jest bardziej elastyczny — obsługuje union, intersection, mapped types, conditional types. Interfejsy lepiej sprawdzają się do definiowania kontraktów publicznych API, type aliasy do złożonych typów. Od TS 4.x różnice maleją, ale declaration merging jest unikalne dla interface.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są generics i po co je stosować?', 'Generics to parametryzowane typy pozwalające pisać reusable kod zachowujący type safety. Zamiast any, deklarujesz placeholder <T>, który jest konkretyzowany przy użyciu. Przykład: function identity<T>(arg: T): T. Ograniczenia: <T extends HasId> wymusza, że T ma pole id. Generics są kluczowe w utility types, kolekcjach i serwisach HTTP.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są conditional types?', 'Conditional types to ternary na poziomie typów: T extends U ? X : Y. Pozwalają na logikę w typach. Z infer wyciągają typy: type ReturnType<T> = T extends (...args: any) => infer R ? R : never. Distributive behavior: gdy T jest union, conditional type jest aplikowany do każdego membera osobno. Kluczowe w budowaniu zaawansowanych utility types.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są mapped types?', 'Mapped types iterują po kluczach i transformują typ: type Readonly<T> = { readonly [K in keyof T]: T[K] }. Modyfikatory: readonly, ?, z + i - (dodanie/usunięcie). as w mapped types (TS 4.1) pozwala remapować klucze: [K in keyof T as `get${Capitalize<K>}`]. Przykłady: Partial, Required, Pick, Record. Bardzo potężne do generowania typów na podstawie istniejących.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są template literal types?', 'Template literal types budują typy stringowe z interpolacji: type Event = `on${Capitalize<string>}`. Przykład: type Color = "red" | "blue"; type BgColor = `bg-${Color}` daje "bg-red" | "bg-blue". W połączeniu z mapped types i conditional types pozwalają na typed routes, CSS class names, event handlers. Potężne do typowania API z konwencjami nazewnictwa.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są type guards i jak je pisać?', 'Type guard to wyrażenie zawężające typ w runtime. Wbudowane: typeof, instanceof, in. Custom: function isFish(pet: Fish | Bird): pet is Fish { return ''swim'' in pet; } — predykat is. Discriminated unions + switch to najlepszy pattern. Assertion functions: function assertDefined<T>(val: T | undefined): asserts val is T. Narrowing jest kluczowy dla type-safe kodu.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest discriminated union?', 'Discriminated union to union type, gdzie każdy member ma wspólne pole „dyskryminator" o literalnym typie: type Shape = { kind: "circle"; radius: number } | { kind: "square"; side: number }. Switch po kind daje exhaustive type checking — TypeScript wie jakie pola są dostępne w każdym case. Dodanie nowego wariantu powoduje compile error w niewyczerpujących switchach (z never).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij Partial<T>, Required<T>, Pick<T,K> i Omit<T,K>.', 'Partial<T> robi wszystkie pola opcjonalne — idealne do update DTO. Required<T> robi wszystkie wymagane. Pick<T, "a" | "b"> wybiera podzbiór pól. Omit<T, "secret"> wyklucza pola. Implementacje oparte na mapped types. Composable: Partial<Pick<User, "name" | "email">>. Kluczowe w codziennym TS — modelują częściowe dane, formy, API responses.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są Record<K,V>, Extract<T,U> i Exclude<T,U>?', 'Record<K, V> tworzy typ obiektowy z kluczami K i wartościami V: Record<string, number> to { [key: string]: number }. Extract<T, U> wyciąga z union T te typy, które pasują do U. Exclude<T, U> usuwa z T typy pasujące do U. Przykład: Exclude<"a"|"b"|"c", "a"> = "b"|"c". Przydatne do filtrowania union types i tworzenia dictionary-like structures.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest declaration merging?', 'Declaration merging to mechanizm, w którym TypeScript łączy wiele deklaracji o tej samej nazwie. Dotyczy interfaces (pola się łączą), namespaces, function overloads. Interfejsy o tej samej nazwie automatycznie się mergują — dlatego można rozszerzać zewnętrzne typy (np. Window, Request). Type aliasy NIE mergują się — to kluczowa różnica. Używane w module augmentation.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest module augmentation?', 'Module augmentation pozwala dodawać typings do istniejących modułów bez modyfikowania ich kodu. Składnia: declare module "express" { interface Request { user?: User } }. Wymaga, by plik był modułem (import/export). Praktyczne: dodanie pól do req w Express, rozszerzenie interfejsów bibliotek, dodanie globalnych typów. Bez tego trzeba by castować na any.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest strictNullChecks i dlaczego warto go włączyć?', 'strictNullChecks sprawia, że null i undefined nie są przypisywalne do innych typów bez jawnego oznaczenia (string | null). Bez tego flaga null może się wkraść wszędzie i powodować runtime errors. Z tą flagą kompilator wymusza obsługę nullable wartości. Włączaj zawsze — łapie ogromną kategorię bugów. Optional chaining (?.) i nullish coalescing (??) pomagają elegancko obsługiwać null.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się unknown od any?', 'any wyłącza type checking — pozwala na dowolne operacje bez weryfikacji (niebezpieczne). unknown jest typem top — możesz przypisać cokolwiek do unknown, ale nie możesz nic z tym zrobić bez narrowingu (type guard, assertion). unknown zmusza do sprawdzenia typu przed użyciem — jest bezpiecznym zamiennikiem any. Używaj unknown do danych z zewnątrz (API responses, user input).', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest typ never?', 'never to typ bottom — żadna wartość go nie ma. Funkcje zwracające never: rzucają exception lub mają infinite loop (nigdy nie returnują). W exhaustive checking: default case w switch na discriminated union — jeśli zapomnimy wariantu, TypeScript pokaże błąd, bo wartość nie jest przypisywalna do never. Conditional types: typ eliminowany z union (Exclude).', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest readonly i jak go używać?', 'readonly modyfikator zapobiega modyfikacji pola po inicjalizacji: readonly name: string. Readonly<T> utility type robi wszystkie pola readonly. ReadonlyArray<T> (lub readonly T[]) blokuje push, pop itd. Uwaga: readonly jest shallow — nested obiekty mogą być mutowane. Dla deep readonly: DeepReadonly z bibliotekami lub rekurencyjny mapped type. as const daje deepest readonly.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest const assertion (as const)?', 'as const zamienia wartość w literal type i dodaje readonly na wszystkich poziomach. const colors = ["red", "blue"] as const daje readonly ["red", "blue"] (tuple z literal types) zamiast string[]. Obiekt z as const ma literal types na wartościach. Przydatne: definiowanie enum-like constów, generowanie union types z tablicy (typeof colors[number] = "red" | "blue").', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa type narrowing w TypeScript?', 'Narrowing to proces zawężania typu w bloku kodu. Mechanizmy: typeof (primitives), instanceof (klasy), in (pola), equality checks, truthiness checks, discriminated unions (switch), custom type guards (is), assertion functions (asserts). TypeScript analizuje control flow — po if (typeof x === "string") w bloku x jest string. Narrowing działa też z optional chaining i nullish coalescing.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest infer keyword w conditional types?', 'infer deklaruje tymczasowy typ w conditional type: type ReturnType<T> = T extends (...args: any) => infer R ? R : never — R jest inferowany z return type. Inne przykłady: type ElementType<T> = T extends (infer U)[] ? U : T wyciąga element z tablicy. infer działa tylko w extends clause. Można mieć wiele infer w jednym wyrażeniu. Potężne do „wyciągania" typów.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest keyof i typeof na poziomie typów?', 'keyof T zwraca union kluczy typu T: keyof { name: string; age: number } = "name" | "age". typeof w kontekście typu (nie runtime) wyciąga typ ze zmiennej: const user = {name: "Jan"}; type User = typeof user. Razem: typeof + keyof do dynamicznego generowania typów z wartości. Object.keys() zwraca string[], keyof daje dokładne klucze — ważna różnica.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest intersection type (T & U)?', 'Intersection łączy typy — wynikowy typ ma WSZYSTKIE pola z obu: type Employee = Person & { company: string }. Różni się od union (T | U), który ma JEDEN z typów. Intersection dla interfejsów działa jak extends/merge. Dla primitives: string & number = never (brak wspólnych wartości). Przydatne do mixowania typów: WithTimestamps<T> = T & { createdAt: Date; updatedAt: Date }.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak typować funkcje wyższego rzędu w TypeScript?', 'Generics są kluczowe: function map<T, U>(arr: T[], fn: (item: T) => U): U[]. Callback z określonym typem: (event: MouseEvent) => void. Overloads dla różnych sygnatur. Higher-order function zwracająca funkcję: function withLogging<T extends (...args: any[]) => any>(fn: T): T. Typy funkcyjne: type Predicate<T> = (item: T) => boolean.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest enum w TypeScript i jakie ma wady?', 'Enum definiuje nazwane stałe: enum Direction { Up, Down }. Numeric enum generuje reverse mapping (dodatkowy JS). String enum ("UP") nie generuje reverse mapping. Wady: enums emitują runtime kod, tree-shaking problematyczny, numeric enums nie są type-safe (można przypisać dowolną liczbę). Alternatywa: const enum (inlinowane) lub union of literals: type Dir = "up" | "down" (zero runtime cost).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest satisfies operator w TypeScript?', 'satisfies (TS 4.9+) sprawdza, czy wartość spełnia typ BEZ poszerzania go. const colors = { red: "#f00" } satisfies Record<string, string> — TypeScript sprawdza zgodność, ale zachowuje literal types (red jest "red", nie string). Bez satisfies musiałbyś wybrać: poszerzony typ (: Record<>) lub brak walidacji (as const). satisfies daje walidację + precyzyjny typ.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa type assertion (as) i kiedy go unikać?', 'Type assertion (x as Type) mówi kompilatorowi „wiem lepiej". Nie wykonuje konwersji runtime — tylko zmienia typ w kompilatorze. Niebezpieczne: jeśli assertion jest błędny, runtime error. Unikaj: preferuj type guards, narrowing, generics. Użyj gdy: TS nie może wywnioskować typu (DOM: document.getElementById() as HTMLInputElement). Double assertion (x as unknown as Y) to red flag.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest function overloading w TypeScript?', 'Overloading pozwala zdefiniować wiele sygnatur dla jednej funkcji: function parse(input: string): number; function parse(input: number): string; function parse(input: string | number): any { ... }. Implementacja musi obsłużyć wszystkie warianty. TS wybiera najlepsze dopasowanie. Używaj gdy zachowanie zależy od typów argumentów. Alternatywa: generic z conditional return type.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest covariance i contravariance w TypeScript?', 'Covariance: jeśli Dog extends Animal, to Array<Dog> jest przypisywalny do Array<Animal> (typy wyjściowe). Contravariance: parametry funkcji — (animal: Animal) => void NIE jest przypisywalny do (dog: Dog) => void (strictFunctionTypes). Bivariance: bez strict — oba kierunki dozwolone (niebezpieczne). Ważne przy typowaniu callbacków i generics z extends.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak tworzyć recursive types w TypeScript?', 'Typy rekurencyjne odwołują się do siebie: type Json = string | number | boolean | null | Json[] | { [key: string]: Json }. Praktyczne: type DeepPartial<T> = { [K in keyof T]?: T[K] extends object ? DeepPartial<T[K]> : T[K] }. Rekurencyjne conditional types (TS 4.1+): type DeepReadonly, Flatten nested arrays. Uwaga na głębokość rekursji — TS ma limit.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest branded/nominal typing w TypeScript?', 'TS ma structural typing — typy są kompatybilne jeśli mają te same pola. Branded types dodają unikalne pole „phantom" dla type safety: type UserId = string & { __brand: "UserId" }. Funkcja acceptująca UserId nie przyjmie zwykłego stringa. Zapobiega pomyleniu UserID z OrderID (oba string). Implementacja: factory function + type assertion. Alternatywa: opaque types z unique symbol.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest strict mode w tsconfig i jakie flagi obejmuje?', 'strict: true włącza zestaw flag: strictNullChecks (null/undefined osobne), strictFunctionTypes (contravariance), strictBindCallApply, strictPropertyInitialization, noImplicitAny (wymusza typy), noImplicitThis, alwaysStrict (JS strict mode). Zawsze włączaj na starcie — dodawanie do istniejącego projektu jest bolesne. Każda flaga łapie real-world bugs.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak typować async/await i Promises w TypeScript?', 'Async function zawsze zwraca Promise<T>: async function fetchUser(): Promise<User>. Await „wypakowuje" Promise: const user = await fetchUser() — user ma typ User. Promise.all zwraca tuple typów: Promise.all([fetchUser(), fetchPosts()]) → [User, Post[]]. Error handling: try/catch z unknown (TS 4.4+) — catch(e: unknown), narrowing e przed użyciem.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest index signature i jakie ma ograniczenia?', 'Index signature: { [key: string]: number } pozwala na dowolne klucze string z wartością number. Ograniczenia: wszystkie pola muszą być kompatybilne z index signature. Record<string, unknown> jest bezpieczniejszy. noUncheckedIndexedAccess (TS 4.1) dodaje | undefined do wyników — wymusza sprawdzenie. Map<K,V> jest alternatywą z lepszym API i brakiem prototype pollution risk.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają tuple types w TypeScript?', 'Tuple to tablica o stałej długości z typem na każdej pozycji: [string, number, boolean]. Nazwane: [name: string, age: number]. Rest element: [string, ...number[]]. Optional: [string, number?]. Readonly: readonly [string, number]. Przydatne jako return type wielu wartości: function usePair(): [value, setter]. Destructuring daje poprawne typy: const [name, age] = tuple.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest utility type NonNullable<T>?', 'NonNullable<T> usuwa null i undefined z union type: NonNullable<string | null | undefined> = string. Implementacja: type NonNullable<T> = T extends null | undefined ? never : T (conditional type z distribution). Przydatne przy danych z API, gdy wiesz, że wartość istnieje po walidacji. Łączy się z Optional chaining: po sprawdzeniu if (x != null) TS sam narrowuje.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są ReturnType<T> i Parameters<T>?', 'ReturnType<T> wyciąga typ zwracany: ReturnType<typeof fetchUser> = Promise<User>. Parameters<T> wyciąga tuple parametrów: Parameters<typeof fn> = [string, number]. Implementacja: conditional type z infer. Przydatne: tworzenie typów z istniejących funkcji bez duplikacji, wrappery zachowujące sygnaturę. ConstructorParameters<T> i InstanceType<T> — analogicznie dla klas.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak typować React props z TypeScript?', 'Interface lub type dla props: interface ButtonProps { label: string; onClick: () => void; variant?: "primary" | "secondary" }. FC<Props> lub function Button(props: ButtonProps). Children: React.ReactNode. Event handlers: React.MouseEvent<HTMLButtonElement>. Generics dla reusable components: Table<T>. PropsWithChildren<P>. ComponentProps<"button"> dla natywnych elementów.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Awaited<T> w TypeScript?', 'Awaited<T> (TS 4.5+) wypakowuje typ z Promise, nawet zagnieżdżonego: Awaited<Promise<Promise<string>>> = string. Zastępuje ręczne: T extends Promise<infer U> ? U : T. Używany wewnętrznie przez Promise.all, Promise.race. Przydatne do typowania wyniku async operacji: type Result = Awaited<ReturnType<typeof fetchData>>.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa structural typing vs nominal typing?', 'TypeScript używa structural typing — typy są kompatybilne jeśli mają zgodną strukturę (shape), niezależnie od nazwy. { name: string } jest przypisywalne do interface Named { name: string }. W C#/Java jest nominal — klasy muszą jawnie implementować interfejs. Structural jest elastyczniejszy, ale mniej precyzyjny. Branded types dodają nominalność tam, gdzie trzeba (UserId vs OrderId).', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest variadic tuple type?', 'Variadic tuples (TS 4.0) pozwalają na spread typów w tuples: type Concat<A extends any[], B extends any[]> = [...A, ...B]. Concat<[1, 2], [3, 4]> = [1, 2, 3, 4]. Przydatne do typowania variadic functions, partial application, pipe/compose. Łączą się z infer: type Last<T extends any[]> = T extends [...any, infer L] ? L : never.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest declaration file (.d.ts)?', 'Declaration file (.d.ts) zawiera tylko typy — bez implementacji. Opisuje kształt biblioteki JS dla TypeScript. Generowany automatycznie (declaration: true w tsconfig) lub ręcznie. DefinitelyTyped (@types/*) to repozytorium deklaracji dla bibliotek bez wbudowanych typów. declare module, declare global rozszerzają istniejące typy. skipLibCheck: true przyspiesza kompilację.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak używać generic constraints?', 'Generic constraint (extends) ogranicza, jakie typy można przekazać: function getProperty<T, K extends keyof T>(obj: T, key: K): T[K]. T extends { id: string } wymaga, by T miał pole id. Multiple constraints: T extends A & B. Default generic: <T = string>. Constraints zapewniają type safety zachowując elastyczność — kompilator wie jakie operacje są bezpieczne na T.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest type predicate i assertion function?', 'Type predicate (is): function isString(x: unknown): x is string { return typeof x === "string" } — zwraca boolean, ale narrowuje typ w callerze. Assertion function (asserts): function assertString(x: unknown): asserts x is string { if (typeof x !== "string") throw Error() } — rzuca lub narrowuje (nie zwraca boolean). Assertion przydatna w validation pipelines.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak TypeScript obsługuje mixins?', 'Mixin to wzorzec dodawania funkcjonalności do klasy bez dziedziczenia. W TS: function Timestamped<T extends Constructor>(Base: T) { return class extends Base { createdAt = new Date() } }. class User extends Timestamped(Base) {}. Wymaga typowania Constructor: type Constructor = new (...args: any[]) => {}. Alternatywa: interface merging + Object.assign w TS.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest using keyword (TS 5.2) i Disposable?', 'using (TS 5.2+) to deklaracja zmiennej z automatycznym cleanup — jak C# using/Python with. Obiekt musi implementować Symbol.dispose (sync) lub Symbol.asyncDispose (async). Po wyjściu z scope dispose jest wywołany automatycznie. Przydatne: połączenia DB, file handles, temporary resources. Eliminuje try/finally boilerplate. Bazuje na TC39 Explicit Resource Management proposal.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak typować wzorzec Builder w TypeScript?', 'Builder z chainable API: class QueryBuilder<T> { where<K extends keyof T>(field: K, value: T[K]): this { ... return this }. this typ pozwala na chaining w podklasach. Generics śledzą stan buildera: AddField<T, K, V> dodaje pole. Wynikowy typ zmienia się z każdym krokiem — kompilator wymusza wymagane pola. Implementacja: mapped types + intersection.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest NoInfer<T> w TypeScript 5.4?', 'NoInfer<T> (TS 5.4+) blokuje inference z danej pozycji. Przykład: function fn<T>(values: T[], defaultValue: NoInfer<T>) — TS nie inferuje T z defaultValue, tylko z values. Rozwiązuje problem, gdy TS infers zbyt szeroką unię z wielu argumentów. Przydatne w API z wieloma parametrami tego samego typu generycznego, gdy chcesz kontrolować skąd TS bierze typ.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementować exhaustive check w TypeScript?', 'Exhaustive check zapewnia obsługę wszystkich wariantów union. Wzorzec: function assertNever(x: never): never { throw new Error("Unexpected: " + x) }. W switch na discriminated union: default: return assertNever(variant). Jeśli zapomnimy case, TS zgłosi błąd — variant nie jest never. Alternatywa: satisfies Record<MyUnion, handler>. Chroni przed dodaniem wariantu bez obsługi.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest path mapping w tsconfig?', 'Path mapping (paths w tsconfig) tworzy aliasy importów: "@app/*": ["src/app/*"], "@shared/*": ["src/shared/*"]. Zamiast "../../../shared/utils" piszesz "@shared/utils". Wymaga baseUrl. Bundler (webpack/vite) musi też znać aliasy. W monorepo: paths do bibliotek. Uwaga: tsc nie transformuje paths w output — potrzebny bundler lub tsc-alias. Czytelniejsze importy.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak używać TS z biblioteką bez typów?', 'Opcje: 1) @types/nazwa z DefinitelyTyped (npm i -D @types/lodash). 2) declare module "lib" { export function fn(): void } w pliku .d.ts. 3) // @ts-ignore lub as any (ostateczność). 4) Napisz własny .d.ts z typami. allowJs + checkJs dla stopniowej migracji JS→TS. skipLibCheck: true pomija sprawdzanie .d.ts (szybsza kompilacja, mniej false positives).', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest project references w TypeScript?', 'Project references (references w tsconfig) dzielą duży projekt na mniejsze z oddzielnymi tsconfig. Każdy sub-project buduje się niezależnie (incremental). tsc --build buduje w kolejności zależności. Zalety: szybsza kompilacja (tylko zmienione projekty), enforcement granic (moduł A nie importuje z wewnętrznego B). Idealne dla monorepo z shared libraries.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak TypeScript obsługuje type widening i narrowing?', 'Widening: TS rozszerza literal typy — let x = "hello" → string, const x = "hello" → "hello". as const blokuje widening. Narrowing: zawężanie typów w control flow — if, typeof, instanceof, in, type guards. TS śledzi control flow i automatycznie narrowuje. Widening jest domyślne dla mutowalnych zmiennych, narrowing działa w warunkach i type guard functions.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym różnią się INNER JOIN, LEFT JOIN, RIGHT JOIN i FULL JOIN?', 'INNER JOIN zwraca wiersze z dopasowaniem w obu tabelach. LEFT JOIN — wszystkie z lewej + dopasowane z prawej (NULL gdy brak). RIGHT JOIN — odwrotnie. FULL JOIN — wszystkie z obu stron (NULL po obu stronach gdy brak dopasowania). LEFT JOIN jest najczęstszy — „pokaż wszystkich userów i ich zamówienia, nawet jeśli nie mają zamówień".', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest CROSS JOIN?', 'CROSS JOIN zwraca iloczyn kartezjański — każdy wiersz z tabeli A z każdym z tabeli B. 10 x 10 = 100 wierszy. Rzadko używany celowo. Zastosowania: generowanie kombinacji (rozmiary x kolory), calendar tables (daty x sloty). Bez warunku ON. Implicitly: SELECT * FROM a, b. Uwaga na wydajność — wynik rośnie wykładniczo.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między WHERE a HAVING?', 'WHERE filtruje wiersze PRZED grupowaniem (GROUP BY) — nie może użyć agregatów. HAVING filtruje grupy PO grupowaniu — może użyć SUM, COUNT itd. Przykład: WHERE status = ''active'' GROUP BY city HAVING COUNT(*) > 10. WHERE jest szybsze (mniej danych do grupowania). Kolejność: FROM → WHERE → GROUP BY → HAVING → SELECT → ORDER BY.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są window functions i podaj przykłady?', 'Window functions wykonują obliczenia na zestawie wierszy (window) powiązanych z bieżącym wierszem, bez grupowania. OVER() definiuje okno. Ranking: ROW_NUMBER(), RANK(), DENSE_RANK(). Agregaty: SUM() OVER(PARTITION BY dept), running total. Offset: LAG(), LEAD(), FIRST_VALUE(). PARTITION BY dzieli, ORDER BY sortuje wewnątrz okna. Niezbędne przy raportach i analityce.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się subquery od CTE?', 'Subquery to zapytanie zagnieżdżone: SELECT * FROM (SELECT ...) sub. CTE (Common Table Expression) to nazwane podzapytanie: WITH active AS (SELECT ...) SELECT * FROM active. CTE jest czytelniejsze, reużywalne w jednym zapytaniu, wspiera rekurencję (WITH RECURSIVE). Wydajność: w PostgreSQL CTE jest optimization fence (do v11), od v12 może być inline. Subquery jest prostsze dla jednorazowych.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest indeks B-tree i kiedy go używać?', 'B-tree to domyślny typ indeksu w większości baz — zbalansowane drzewo umożliwiające wyszukiwanie w O(log n). Idealny dla: equality (=), range (<, >, BETWEEN), ORDER BY, GROUP BY. Indeks na (city, name) wspiera WHERE city = ''X'' i WHERE city = ''X'' AND name = ''Y'', ale NIE sam WHERE name = ''Y'' (leftmost prefix rule). Dodaj na kolumnach w WHERE, JOIN, ORDER BY.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest indeks GIN i kiedy go używać?', 'GIN (Generalized Inverted Index) indeksuje wartości wewnątrz kontenerów: tablice, JSONB, tsvector (full-text search). Dla JSONB: WHERE data @> ''{"status": "active"}''. Dla tablic: WHERE tags @> ARRAY[''sql'']. Wolniejszy zapis (aktualizacja odwróconego indeksu), ale szybki odczyt. GiST to alternatywa dla danych geometrycznych i zakresów (range types).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest composite index i jakie ma zasady?', 'Composite index to indeks na wielu kolumnach: CREATE INDEX idx ON orders(user_id, created_at). Zasada leftmost prefix: indeks (A, B, C) wspiera zapytania na A, A+B, A+B+C, ale nie na B ani C osobno. Kolejność kolumn ma znaczenie — najpierw kolumny z equality, potem range. Covering index (INCLUDE) dodaje kolumny do liści, eliminując index-only scan.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak czytać wynik EXPLAIN ANALYZE?', 'EXPLAIN ANALYZE wykonuje zapytanie i pokazuje plan z rzeczywistymi czasami. Kluczowe: Seq Scan (full table scan — brak indeksu), Index Scan (OK), Nested Loop (dużo iteracji = wolne), Sort (spilluje na dysk?), actual time, rows (estimated vs actual — duża rozbieżność = nieaktualne statystyki → ANALYZE). Buffers: shared hit (cache) vs read (disk). Cost to estymata, actual time to prawda.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest normalizacja bazy danych?', 'Normalizacja eliminuje redundancję i anomalie danych. 1NF: atomowe wartości, brak powtarzających się grup. 2NF: 1NF + brak częściowych zależności od klucza złożonego. 3NF: 2NF + brak zależności tranzytywnych (kolumna zależy od nie-klucza). BCNF: silniejsza 3NF. W praktyce 3NF wystarcza. Denormalizacja jest OK dla wydajności odczytu (raporty, cache).', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest ACID w kontekście transakcji?', 'ACID to właściwości transakcji: Atomicity (wszystko albo nic — rollback), Consistency (dane przechodzą z jednego spójnego stanu do drugiego), Isolation (równoległe transakcje nie interferują), Durability (po COMMIT dane przetrwają crash). PostgreSQL gwarantuje ACID. NoSQL często oferuje BASE (Basically Available, Soft state, Eventually consistent) zamiast ACID.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są poziomy izolacji transakcji?', 'Read Uncommitted: widzi niezacommitowane dane (dirty read). Read Committed (domyślny PG): widzi tylko committed (no dirty reads, ale non-repeatable reads). Repeatable Read: snapshot na starcie (no phantom reads w PG). Serializable: pełna izolacja — jakby transakcje szły sekwencyjnie (najwolniejszy). Wyższy poziom = mniej anomalii, ale więcej locków/retry. PG nie ma true Read Uncommitted.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest deadlock i jak go unikać?', 'Deadlock to sytuacja, gdy dwie transakcje czekają na siebie nawzajem — żadna nie może kontynuować. Baza wykrywa i zabija jedną (rollback). Unikanie: lockuj zasoby w stałej kolejności, krótkie transakcje, unikaj trzymania locków między interakcjami z userem. Advisory locks dla custom logiki. Monitoring: pg_stat_activity, deadlock_timeout w PostgreSQL.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest problem N+1 w kontekście bazy danych?', 'N+1: pobierasz N użytkowników (1 query), potem dla każdego pobierasz posty (N queries). Razem N+1 zapytań zamiast 1-2. Rozwiązania: JOIN (1 query), WHERE id IN (...) (batch — 2 queries), eager loading w ORM (include/with). Wykrywanie: logowanie zapytań, pg_stat_statements, APM. W GraphQL: DataLoader. N+1 to jedna z najczęstszych przyczyn wolnych API.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest partycjonowanie tabel?', 'Partitioning dzieli dużą tabelę na mniejsze fizyczne części (partycje) z jednym logicznym interfejsem. Typy: RANGE (np. po dacie — miesiące/lata), LIST (po kategorii), HASH (równomierny rozkład). Zalety: partition pruning (query skanuje tylko relevantne partycje), łatwe archiwizowanie (DROP PARTITION), parallel query. PostgreSQL: PARTITION BY RANGE (created_at).', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest materialized view?', 'Materialized view to wynik zapytania przechowywany fizycznie — jak tabela cache. CREATE MATERIALIZED VIEW mv AS SELECT ... . REFRESH MATERIALIZED VIEW odświeża dane (CONCURRENTLY bez blokowania odczytu). Idealny dla ciężkich raportów, dashboardów, denormalizacji. Wadą jest stale data między refreshami. Indeksy na matview przyspieszają odczyty. Scheduler (pg_cron) do automatycznego refresh.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różnią się stored procedures od functions w PostgreSQL?', 'Function: wywołana w SELECT, zwraca wartość, działa w transakcji callera, nie może COMMIT/ROLLBACK wewnątrz. Procedure (PG 11+): wywołana CALL, może zarządzać transakcjami wewnątrz (COMMIT/ROLLBACK), nie zwraca wartości przez RETURN (ale przez OUT params). Functions do obliczeń i transformacji danych, procedures do złożonej logiki biznesowej z wieloma transakcjami.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest trigger w bazie danych?', 'Trigger to funkcja wykonywana automatycznie BEFORE/AFTER/INSTEAD OF operacji INSERT/UPDATE/DELETE. Zastosowania: audit log, walidacja, aktualizacja updated_at, synchronizacja denormalizowanych danych. Zmienne: NEW (nowy wiersz), OLD (stary). Uwaga: triggery utrudniają debugowanie (ukryta logika), spowalniają operacje. Preferuj logikę w aplikacji; triggery na audit/timestamps.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa VACUUM w PostgreSQL?', 'PostgreSQL używa MVCC — UPDATE/DELETE nie usuwają wierszy fizycznie, tylko oznaczają jako „dead". VACUUM odzyskuje przestrzeń z dead tuples. AUTOVACUUM działa automatycznie (konfigurowalny próg). VACUUM FULL przepisuje tabelę (wymaga exclusive lock, zwraca przestrzeń OS). Monitoruj: pg_stat_user_tables.n_dead_tup. Źle skonfigurowany autovacuum = table bloat i wolne query.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest MVCC?', 'MVCC (Multi-Version Concurrency Control) to mechanizm, w którym każda transakcja widzi snapshot danych z momentu jej startu. Pisanie nie blokuje czytania i odwrotnie. PostgreSQL implementuje MVCC przez xmin/xmax na każdym wierszu — wersje wierszy współistnieją. Pozwala na wysoką współbieżność. Koszt: dead tuples wymagające VACUUM. Alternatywa: pesymistyczne lockowanie (gorsze dla read-heavy).', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest partial index?', 'Partial index to indeks z warunkiem WHERE: CREATE INDEX idx ON orders(created_at) WHERE status = ''pending''. Indeksuje tylko wiersze spełniające warunek — mniejszy rozmiar, szybsze aktualizacje. Idealny gdy query zawsze filtruje po danym warunku. Przykład: indeks na active users (WHERE deleted_at IS NULL) gdy 90% jest deleted. Planner użyje go tylko gdy query pasuje do WHERE.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zoptymalizować wolne zapytanie z wieloma JOINami?', 'Kroki: 1) EXPLAIN ANALYZE — zidentyfikuj bottleneck (Seq Scan, duże Nested Loop). 2) Indeksy na JOIN kluczach i WHERE. 3) Sprawdź statystyki (ANALYZE table). 4) Zmień kolejność JOINów (planner robi to sam, ale check). 5) CTE zamiast correlated subquery. 6) Materialized view dla ciężkich agregacji. 7) LIMIT wcześnie. 8) Denormalizacja jako last resort.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest recursive CTE?', 'WITH RECURSIVE cte AS (base_query UNION ALL recursive_query) SELECT * FROM cte. Base query: punkt startowy. Recursive: odwołuje się do cte. Zastosowania: hierarchie (drzewo kategorii, org chart), grafy (najkrótsza ścieżka), generowanie serii. Wymaga warunku stopu (WHERE level < 10 lub brak wyników). Uwaga na infinite loops — dodaj LIMIT lub cycle detection.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest cursor-based pagination vs offset-based?', 'Offset: LIMIT 20 OFFSET 100 — prosty, ale wolny dla dużych offsetów (skanuje i odrzuca wiersze). Cursor: WHERE id > last_seen_id ORDER BY id LIMIT 20 — stała wydajność niezależnie od strony. Cursor wymaga stabilnego unikalnego klucza sortowania. Offset pozwala na „skacz do strony 50", cursor nie. Cursor jest standardem w API z dużymi zbiorami danych.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest connection pooling i po co?', 'Connection pool utrzymuje pulę otwartych połączeń do bazy, reużywanych między requestami. Otwarcie połączenia jest kosztowne (TCP, TLS, auth). PgBouncer: transaction mode (połączenie na czas transakcji — najefektywniejszy), session mode. Supabase/Vercel mają built-in pooler. Konfiguracja: max connections (baza), pool_size (aplikacja). Za dużo połączeń = degradacja bazy.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają indeksy w kontekście INSERT/UPDATE/DELETE?', 'Każdy indeks spowalnia zapisy — przy INSERT/UPDATE/DELETE baza musi zaktualizować wszystkie indeksy na tabeli. Dlatego: nie indeksuj na zapas, usuwaj nieużywane indeksy (pg_stat_user_indexes.idx_scan = 0). Dla bulk insert: DROP INDEX → INSERT → CREATE INDEX jest szybsze. Partial index i covering index minimalizują overhead. Balans: szybkie odczyty vs szybkie zapisy.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest JSONB w PostgreSQL i kiedy go używać?', 'JSONB przechowuje JSON w binarnym formacie — szybkie operacje, indeksowalny (GIN). Operatory: ->> (tekst), -> (JSON), @> (contains), ? (has key). Kiedy: semi-structured data, zmienny schemat, metadata, ustawienia. Kiedy NIE: dane relacyjne z wieloma JOINami, dane wymagające referential integrity. JSONB path queries (@@) od PG 12. Indeks GIN na jsonb_path_ops jest mniejszy.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest row-level security (RLS)?', 'RLS pozwala definiować polityki dostępu na poziomie wierszy: CREATE POLICY user_policy ON orders FOR SELECT USING (user_id = current_setting(''app.user_id'')). Po ALTER TABLE orders ENABLE ROW LEVEL SECURITY, każdy SELECT/UPDATE/DELETE jest filtrowany automatycznie. Supabase intensywnie używa RLS. Polityki USING (SELECT) i WITH CHECK (INSERT/UPDATE). Superuser omija RLS.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest foreign key i jakie ma ON DELETE opcje?', 'Foreign key zapewnia referential integrity — wartość w kolumnie musi istnieć w referenced table. ON DELETE opcje: CASCADE (usuń powiązane), SET NULL (ustaw NULL), SET DEFAULT, RESTRICT (blokuj jeśli ma powiązania), NO ACTION (domyślny, check na końcu transakcji). CASCADE jest wygodny ale niebezpieczny — przypadkowe usunięcie kaskaduje. Preferuję RESTRICT + soft delete.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak monitorować wydajność PostgreSQL?', 'Narzędzia: pg_stat_statements (top zapytania po czasie/wywołaniach), pg_stat_user_tables (seq scan, dead tuples), pg_stat_user_indexes (użycie indeksów), pg_stat_activity (aktywne połączenia/locki). Metryki: connection count, cache hit ratio (>99%), transaction rate, replication lag. Zewnętrzne: pganalyze, Datadog, Grafana+Prometheus z postgres_exporter. auto_explain loguje wolne plany.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest lateral join?', 'LATERAL JOIN pozwala subquery odwoływać się do kolumn z wcześniejszych tabel w FROM: SELECT * FROM users u, LATERAL (SELECT * FROM orders WHERE user_id = u.id ORDER BY created_at DESC LIMIT 3) o. Działa jak foreach — dla każdego usera wykona subquery. Przydatne: top-N per group, zależne subqueries. Bez LATERAL subquery nie widzi outer query columns.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są prepared statements i dlaczego są ważne?', 'Prepared statement to prekompilowane zapytanie z placeholderami ($1, $2) zamiast wartości. Baza parsuje i planuje raz, wykonuje wiele razy z różnymi parametrami. Dwie korzyści: bezpieczeństwo (ochrona przed SQL injection — parametry nie są interpretowane jako SQL) i wydajność (reuse plan). Każdy ORM i driver bazodanowy powinien używać prepared statements domyślnie.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest database replication?', 'Replication kopiuje dane z primary do replica(s). Streaming replication (PG): synchronous (gwarantuje spójność, wyższy latency) lub asynchronous (szybsze, ryzyko utraty danych). Logical replication: selektywna (wybrane tabele), cross-version. Use cases: read replicas (skalowanie odczytu), HA failover, backup, analytics na replice. Replication lag to kluczowa metryka.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektować schemat dla systemu tagów (many-to-many)?', 'Trzy tabele: items (id, name), tags (id, name UNIQUE), item_tags (item_id FK, tag_id FK, PRIMARY KEY (item_id, tag_id)). Indeks na (tag_id, item_id) dla wyszukiwania po tagu. Query: JOIN item_tags ON ... JOIN tags ON ... WHERE tag.name IN (...) GROUP BY item.id HAVING COUNT(*) = N (all tags). Alternatywa: array column z GIN index — prostsze, ale bez referential integrity.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest UPSERT (INSERT ON CONFLICT)?', 'UPSERT to INSERT, który przy konflikcie (unique constraint) wykonuje UPDATE zamiast błędu. PostgreSQL: INSERT INTO ... ON CONFLICT (email) DO UPDATE SET name = EXCLUDED.name. DO NOTHING ignoruje konflikt. EXCLUDED referuje do wartości, które miały być wstawione. Przydatne: synchronizacja danych, idempotentne operacje. Atomowe — bez race condition między SELECT a INSERT.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest covering index (INCLUDE)?', 'Covering index zawiera wszystkie kolumny potrzebne w query — baza nie musi sięgać do tabeli (index-only scan). CREATE INDEX idx ON orders(user_id) INCLUDE (total, status). Kolumny w INCLUDE nie są częścią klucza (nie służą do wyszukiwania), ale są przechowywane w liściach indeksu. Drastycznie przyspiesza query, które SELECT-ują kilka kolumn z dużej tabeli.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest GROUP BY ROLLUP/CUBE/GROUPING SETS?', 'Rozszerzenia GROUP BY dla raportów. GROUPING SETS: grupuj po wielu kombinacjach w jednym query. ROLLUP (a, b): grupuje po (a,b), (a), () — hierarchiczne subtotale. CUBE (a, b): wszystkie kombinacje — (a,b), (a), (b), (). Zastępują UNION ALL wielu GROUP BY. GROUPING() function rozróżnia NULL od subtotalu. Potężne do dashboardów i raportów.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługiwać soft delete w bazie danych?', 'Soft delete: zamiast DELETE, ustawiasz deleted_at = now(). Zalety: odwracalność, audit trail. Wyzwania: każdy query musi dodać WHERE deleted_at IS NULL (łatwo zapomnieć — użyj view lub RLS), foreign keys nie chronią przed „sierotem", indeksy rosną. Partial index: WHERE deleted_at IS NULL. Alternatywa: archive table (przenoś usunięte rekordy). Supabase: RLS z policy na deleted_at.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest CTid w PostgreSQL?', 'ctid to systemowa kolumna identyfikująca fizyczną lokalizację wiersza (block_number, tuple_index). Zmienia się po VACUUM FULL lub UPDATE (nowa wersja wiersza). Użyteczna: deduplication (DELETE FROM t WHERE ctid NOT IN (SELECT min(ctid) FROM t GROUP BY unique_cols)), debugging. Nie używaj jako trwałego identyfikatora — niestabilna. Odpowiednik ROWID w Oracle.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest TOAST w PostgreSQL?', 'TOAST (The Oversized-Attribute Storage Technique) to mechanizm przechowywania wartości > 2KB. PG kompresuje (pglz lub lz4) i/lub dzieli na chunki przechowywane w osobnej tabeli TOAST. Strategie per kolumna: PLAIN (bez TOAST), EXTENDED (kompresja + external), EXTERNAL (only external), MAIN (kompresja, external jako last resort). Transparentne dla użytkownika.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementować full-text search w PostgreSQL?', 'tsvector przechowuje znormalizowane tokeny, tsquery definiuje wyszukiwanie. WHERE to_tsvector(''polish'', content) @@ to_tsquery(''polish'', ''angular & typescript''). Indeks GIN na tsvector. Ranking: ts_rank(), ts_rank_cd(). Wagi: setweight() dla tytułu vs treści. Trigram (pg_trgm) dla fuzzy search i LIKE. Dla zaawansowanych potrzeb: Elasticsearch.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest optimistic locking w SQL?', 'Optimistic locking zakłada brak konfliktów. Implementacja: kolumna version (integer). UPDATE orders SET total = 100, version = version + 1 WHERE id = 1 AND version = 5. Jeśli affected_rows = 0 — ktoś zmienił wcześniej, retry. Alternatywa: updated_at timestamp. Lekki — brak locków w bazie. Idealny dla web apps z niskim contention. Pessimistic: SELECT FOR UPDATE.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest advisory lock w PostgreSQL?', 'Advisory lock to lock na arbitralnej wartości (integer) — nie na wierszu/tabeli. pg_advisory_lock(123) blokuje do zwolnienia lub końca sesji. pg_try_advisory_lock() nie blokuje, zwraca boolean. Zastosowania: distributed locking, rate limiting, zapobieganie równoległemu uruchomieniu (np. migration, cron job). Transaction-level: pg_advisory_xact_lock() — auto-release po transakcji.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa EXPLAIN w PostgreSQL — koszt, wiersze, czas?', 'EXPLAIN pokazuje plan bez wykonania (estimaty). EXPLAIN ANALYZE wykonuje i pokazuje actual. cost=0.00..10.50: startup cost..total cost (arbitrary units). rows: estymowana liczba wierszy. actual time: ms. Planning Time + Execution Time. Seq Scan cost proporcjonalny do rozmiaru tabeli. Index Scan ma wyższy startup cost, niższy total dla selektywnych queries. Buffers (ANALYZE + BUFFERS): hit (cache) vs read (disk).', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest expression index?', 'Expression index indeksuje wynik wyrażenia: CREATE INDEX idx ON users (LOWER(email)). Query WHERE LOWER(email) = ''jan@test.pl'' użyje tego indeksu. Bez niego — Seq Scan, bo indeks na email nie pasuje do LOWER(email). Przykłady: EXTRACT(year FROM created_at), (data->>''type''), unaccent(name). Przydatne gdy query zawsze stosuje funkcję na kolumnie.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest pg_stat_statements?', 'pg_stat_statements to rozszerzenie PostgreSQL śledzące statystyki wszystkich wykonanych zapytań: total_time, calls, mean_time, rows, shared_blks_hit/read. Kluczowe do identyfikacji: najwolniejszych zapytań (ORDER BY total_time DESC), najczęstszych (calls), z największym I/O. Reset: pg_stat_statements_reset(). Powinno być włączone na każdej produkcyjnej bazie.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak migrować schemat bazy bez downtime?', 'Expand-contract pattern: 1) Dodaj nową kolumnę (nullable, z default), 2) Deploy kod piszący do obu kolumn, 3) Backfill starych danych, 4) Deploy kod czytający z nowej, 5) Usuń starą kolumnę. Additive changes: ADD COLUMN (instant w PG 11+ z non-volatile default), CREATE INDEX CONCURRENTLY (bez lock). Nigdy: ALTER COLUMN TYPE na dużej tabeli (rewrite), DROP COLUMN w jednym deploy.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest logical replication vs physical replication?', 'Physical: replika bitowa WAL stream — identyczna kopia, ten sam PG version, cała instancja. Logical: replikuje zmiany na poziomie tabeli/row — selektywna, cross-version, cross-platform. Logical: publication/subscription model. Use cases physical: HA failover, read replicas. Logical: migracja między wersjami, selective sync, CDC (Change Data Capture) do Kafka/Elasticsearch.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektować schemat dla hierarchii (drzewo kategorii)?', 'Opcje: 1) Adjacency list: parent_id FK — proste, ale recursive query dla drzewa. 2) Materialized path: path = "1/4/7" — LIKE ''1/4/%'' szybkie, ale rebalancing. 3) Nested sets: lft/rgt — szybki odczyt, wolny zapis. 4) ltree extension (PG): natywny typ drzewa z operatorami. 5) Closure table: osobna tabela ancestor/descendant. Adjacency + recursive CTE jest najprostsze i zazwyczaj wystarczające.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest pg_cron i do czego go używać?', 'pg_cron to rozszerzenie PostgreSQL umożliwiające scheduling zadań w bazie (cron syntax). SELECT cron.schedule(''vacuum'', ''0 3 * * *'', ''VACUUM ANALYZE orders''). Zastosowania: REFRESH MATERIALIZED VIEW, archiwizacja starych danych, czyszczenie expired sessions, statystyki. Alternatywa: external cron + psql, pg_agent. W Supabase pg_cron jest dostępny out-of-the-box.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym różni się git rebase od git merge?', 'Merge tworzy merge commit łączący dwie gałęzie — zachowuje pełną historię z rozgałęzieniami. Rebase przenosi commity z brancha na szczyt target brancha — liniowa historia, czytelniejsza, ale przepisuje commity (nowe hashe). Zasada: rebase lokalnych zmian, merge publicznych branchy. Nigdy nie rebase''uj tego, co już pushowałeś (shared history).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest git cherry-pick?', 'Cherry-pick kopiuje pojedynczy commit z innego brancha na bieżący: git cherry-pick <hash>. Tworzy nowy commit z tym samym patchem ale innym hashem. Zastosowania: hotfix z develop na main, przeniesienie konkretnej zmiany bez merge. Uwaga: może powodować konflikty i duplikację logiki. Preferuj merge/rebase dla większych zmian. --no-commit pozwala zmodyfikować przed commitem.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest git bisect?', 'Git bisect to binarne wyszukiwanie commita, który wprowadził bug. git bisect start, bisect bad (bieżący), bisect good <hash> (znany dobry). Git checkout''uje środkowy commit — testujesz i mówisz good/bad. W O(log n) krokach znajdujesz winny commit. Automatyzacja: git bisect run ./test.sh. Niezastąpione przy regresji w projekcie z dużą historią.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest git reflog?', 'Reflog to log WSZYSTKICH zmian HEAD — nawet tych „utraconych" po reset, rebase, amend. git reflog pokazuje historię ruchów HEAD. Ratunkowy: git reset --hard HEAD@{3} przywraca stan sprzed 3 operacji. Reflog jest lokalny (nie pushowany), trzymany domyślnie 90 dni. Niezastąpiony gdy zrobisz błędny reset --hard lub rebase. „Git nigdy niczego nie traci" — dzięki reflogowi.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Porównaj Git Flow i trunk-based development.', 'Git Flow: long-lived branches (main, develop, feature/*, release/*, hotfix/*). Formalne releasy. Odpowiedni dla wersjonowanego software. Trunk-based: wszyscy commitują do main, short-lived feature branches (max 1-2 dni), feature flags. Wymaga: CI, dobre testy, small increments. TBD preferowany w CI/CD z frequent deploys. Git Flow dla regulated/versioned products.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest CI/CD pipeline i jakie ma typowe etapy?', 'Pipeline to zautomatyzowany proces od commitu do produkcji. Etapy: 1) Checkout kodu, 2) Install dependencies, 3) Lint/format check, 4) Build, 5) Unit tests, 6) Integration tests, 7) Security scan (SAST, dependency audit), 8) Build artifact/image, 9) Deploy staging, 10) E2E tests, 11) Deploy production. Fast feedback: fail early. Narzędzia: GitHub Actions, GitLab CI, Jenkins.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Docker i czym jest Dockerfile?', 'Docker buduje obrazy z Dockerfile — sekwencji instrukcji: FROM (bazowy obraz), COPY/ADD (pliki), RUN (komendy), ENV, EXPOSE, CMD/ENTRYPOINT. Każda instrukcja tworzy warstwę (layer) — cached jeśli się nie zmienił. Multi-stage build: osobny stage na build (z devDependencies) i runtime (lekki obraz). .dockerignore wyklucza pliki. Obraz jest immutable, kontener jest uruchomioną instancją.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest multi-stage build w Dockerze?', 'Multi-stage build używa wielu FROM w jednym Dockerfile. Pierwszy stage: buduje aplikację (z devDependencies, kompilatorem). Drugi stage: kopiuje tylko artefakty (COPY --from=builder) do lekkiego obrazu (alpine/distroless). Efekt: mały finalny obraz bez build tools i źródeł. Przykład: Node.js — build stage z npm ci, production stage z node:alpine i skopiowanym dist/.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są Docker volumes i kiedy ich używać?', 'Volume to mechanizm persistowania danych poza kontenerem (filesystem kontenera jest ephemeral). Typy: named volumes (Docker zarządza), bind mounts (mapowanie katalogu hosta), tmpfs (tylko RAM). Zastosowania: bazy danych (pgdata), upload files, shared state między kontenerami. docker-compose: volumes sekcja. Backup: docker cp lub volume driver. Nie przechowuj stanu w kontenerze.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Docker Compose i do czego służy?', 'Docker Compose to narzędzie do definiowania multi-container applications w pliku docker-compose.yml. Definiujesz: services (kontenery), networks, volumes. docker compose up startuje wszystko. Idealny dla dev environment: app + baza + redis + queue. depends_on kontroluje kolejność, healthcheck czeka na gotowość. Override: docker-compose.override.yml dla dev. Nie do produkcji — tam Kubernetes.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Kubernetes i jakie problemy rozwiązuje?', 'Kubernetes (K8s) to orkiestrator kontenerów: automatyczny deployment, skalowanie, self-healing. Kluczowe koncepty: Pod (grupa kontenerów), Deployment (desired state), Service (networking), Ingress (HTTP routing), ConfigMap/Secret (konfiguracja). K8s rozwiązuje: auto-scaling (HPA), rolling updates, service discovery, load balancing, resource management. Managed: EKS, GKE, AKS.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się blue-green od canary deployment?', 'Blue-green: dwa identyczne środowiska, przełączasz ruch z blue na green naraz (zero downtime, szybki rollback, podwójne zasoby). Canary: nowa wersja dostaje mały % ruchu (np. 5%), monitorujesz metryki, stopniowo zwiększasz. Canary wykrywa problemy wcześnie z minimalnym blast radius. Blue-green jest prostszy. K8s: Argo Rollouts, Flagger dla canary.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Infrastructure as Code (IaC)?', 'IaC zarządza infrastrukturą (serwery, sieci, bazy) przez kod zamiast manualnych operacji. Deklaratywne: Terraform (HCL, state file, multi-cloud), CloudFormation (AWS). Imperatywne: Pulumi (TS/Python). Configuration management: Ansible (serwery). Zalety: wersjonowanie, code review, powtarzalność, disaster recovery. GitOps: Git jako source of truth, ArgoCD/Flux synchronizuje.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest monitoring vs logging vs tracing?', 'Monitoring: zbieranie metryk (CPU, memory, request rate, error rate) i alertowanie. Prometheus + Grafana. Logging: zapis zdarzeń (structured JSON, levels). ELK Stack, Loki. Tracing: śledzenie requestu przez wiele serwisów — span ID, trace ID. Jaeger, Zipkin. Razem tworzą three pillars of observability. Correlation ID łączy logi z trace''ami. Każdy filar odpowiada na inny typ pytania o system.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są SLI, SLO, SLA w kontekście DevOps?', 'SLI (Service Level Indicator): mierzalna metryka (latency p99, availability %). SLO (Objective): wewnętrzny cel (99.9% availability). SLA (Agreement): kontrakt z klientem z konsekwencjami. Error budget = 100% - SLO. Gdy budget się wyczerpie: stop feature work, focus na reliability. SRE (Site Reliability Engineering) zarządza tym procesem. Mierz to, co wpływa na user experience.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa git stash?', 'git stash zapisuje lokalne zmiany (staged + unstaged) na stos i przywraca clean working directory. git stash pop przywraca i usuwa ze stosu. git stash apply przywraca bez usuwania. git stash list — lista. git stash drop — usuń. Zastosowania: szybkie przełączenie brancha bez commitowania WIP, testowanie czystego stanu. --include-untracked stashuje też nowe pliki.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest git interactive rebase?', 'git rebase -i HEAD~5 pozwala na modyfikację ostatnich 5 commitów: pick (zostaw), squash (połącz z poprzednim), fixup (squash bez message), reword (zmień message), edit (zatrzymaj do edycji), drop (usuń). Zastosowania: cleanup historii przed merge, squash WIP commitów, reorder. Tylko na lokalne commity — nie przepisuj shared history.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest .gitignore i jakie pliki powinno ignorować?', '.gitignore definiuje wzorce plików, które Git nie śledzi. Typowe: node_modules/, dist/, build/, .env*, *.log, .DS_Store, .idea/, .vscode/ (opcjonalnie). Wzorce: * (wildcard), ** (recursive), ! (negate). .gitignore w root, ale mogą być per directory. Jeśli plik już jest tracked, gitignore go nie usunie — trzeba git rm --cached. gitignore.io generuje templates.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak wygląda Twoja strategia branchowania?', 'Preferuję trunk-based z short-lived feature branches. Konwencja: feature/TICKET-123-description, fix/..., chore/.... PR = 1 logical change. Squash merge do main (czysta historia). Protected main: CI musi przejść, wymagany review. Release: tag na main lub release branch (jeśli potrzeba). Hotfix: branch z main, merge z powrotem. Ważne: branch żyje max 2-3 dni.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Docker networking?', 'Docker sieci: bridge (domyślna, kontenery komunikują się po nazwie w docker-compose), host (kontener dzieli sieć hosta), none (izolacja). docker-compose domyślnie tworzy bridge network — kontenery widzą się po nazwie serwisu. Exposed ports (EXPOSE/ports) mapują porty kontenera na hosta. W K8s: ClusterIP (internal), NodePort, LoadBalancer, Ingress.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zabezpieczasz sekrety w CI/CD?', 'Nigdy w kodzie/repo! Sekrety jako encrypted variables w CI (GitHub Secrets, GitLab CI Variables). Runtime: environment variables, Vault (HashiCorp), AWS Secrets Manager, SOPS (encrypted files w Git). Docker: Docker secrets (Swarm), K8s Secrets (base64, nie encrypted — użyj sealed-secrets lub external-secrets). Rotacja sekretów. Audit access. Least privilege.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest GitHub Actions i jak działa?', 'GitHub Actions to CI/CD wbudowane w GitHub. Workflow (.github/workflows/*.yml): trigger (push, PR, schedule, manual), jobs (runner: ubuntu-latest), steps (uses: actions/*, run: commands). Matrix strategy: testuj na wielu wersjach. Cache (actions/cache) dla node_modules. Secrets: ${{ secrets.API_KEY }}. Reusable workflows. Marketplace z gotowymi actions.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Docker layer caching i jak go optymalizować?', 'Każda instrukcja Dockerfile tworzy warstwę. Docker cache''uje warstwy — zmiana invalidity tę i kolejne warstwy. Optymalizacja: COPY package*.json . i RUN npm ci PRZED COPY . . (dependencies cache''owane gdy się nie zmieniły). Porządek: rzadko zmieniane na górze. Łącz RUN (mniej warstw). .dockerignore wyklucza niepotrzebne pliki. Multi-stage: mniejszy kontekst buildu.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest rollback strategy?', 'Strategia cofania wadliwego deploy. Opcje: redeploy poprzedniej wersji (artifact/image), blue-green switch back, feature flag off, database rollback migration. Wymaga: immutable artifacts z wersją, backward-compatible migrations, health checks wykrywające problemy. Automatyczny rollback: K8s rollout undo, CI/CD po failed health check. Testuj rollback regularnie — nietestowany rollback nie zadziała.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak monitorujesz kontenery w produkcji?', 'Container metrics: CPU, memory, restart count, network I/O. K8s: kubectl top, metrics-server, Prometheus + kube-state-metrics. Logi: stdout/stderr → log driver → aggregator (Loki, ELK). Alerting: Prometheus Alertmanager, PagerDuty. Dashboard: Grafana. Health checks: liveness probe (restart), readiness probe (traffic). Resource limits (requests/limits) zapobiegają noisy neighbor.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest git hook i jakie są przydatne hooki?', 'Git hooks to skrypty uruchamiane automatycznie przy operacjach Git. Client-side: pre-commit (lint, format), commit-msg (walidacja formatu), pre-push (testy). Server-side: pre-receive, post-receive. Narzędzia: Husky (JS), lefthook, pre-commit (Python). lint-staged uruchamia lint tylko na staged plikach. Conventional commits: commitlint sprawdza format „feat: ...", „fix: ...".', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Terraform state i jak go zarządzać?', 'Terraform state (.tfstate) to JSON mapujący zasoby w kodzie na rzeczywiste ID w chmurze. Bez state: Terraform nie wie co istnieje. Remote backend (S3 + DynamoDB lock, Terraform Cloud) — współdzielony, lockowany. State zawiera sekrety — encrypt at rest. terraform plan porównuje state z kodem i realnym stanem. State drift: terraform refresh. Nigdy nie edytuj state ręcznie.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak debugujesz kontener w produkcji?', 'Kroki: 1) kubectl logs pod-name (logi), 2) kubectl describe pod (events, status), 3) kubectl exec -it pod -- sh (wejdź do kontenera), 4) kubectl port-forward (dostęp do serwisu). Ephemeral debug containers: kubectl debug. Distributed tracing (Jaeger) dla cross-service issues. Jeśli kontener crashuje: check OOMKilled (memory limit), CrashLoopBackOff (logi z poprzedniego run).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest GitOps?', 'GitOps to podejście, w którym Git jest single source of truth dla infrastruktury i deploymentu. Operator (ArgoCD, Flux) monitoruje repo i synchronizuje klaster z desired state w Git. Zalety: audit trail (Git history), rollback (git revert), code review na infrastrukturę, deklaratywność. Pull-based: operator pobiera zmiany (bezpieczniejsze niż CI push do produkcji).', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zminimalizować rozmiar obrazu Docker?', 'Techniki: 1) Lekki bazowy obraz (alpine, distroless, slim). 2) Multi-stage build (kopiuj tylko artefakty). 3) Łącz RUN (mniej warstw). 4) Czyszcz cache w tym samym RUN (apt-get clean, rm -rf /var/lib/apt/lists/*). 5) .dockerignore. 6) Nie instaluj devDependencies w finalnym stage. Mały obraz: szybszy pull, mniejsza powierzchnia ataku, mniej kosztów storage.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest conventional commits?', 'Conventional Commits to konwencja formatu commit messages: type(scope): description. Typy: feat (nowa funkcja), fix (bug), docs, chore, refactor, test, style, perf, ci. Breaking change: feat!: lub BREAKING CHANGE w footer. Automatyzacja: semantic-release generuje wersje i changelog na podstawie commitów. commitlint + Husky wymusza format. Czytelna historia i automatyczne wersjonowanie.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest health check w kontekście deploymentu?', 'Health check to endpoint (/health, /ready) zwracający status aplikacji. Liveness: „czy aplikacja działa?" — restart jeśli nie. Readiness: „czy może obsługiwać ruch?" — nie kieruj traffic jeśli nie (np. warmup, dependency down). K8s: livenessProbe, readinessProbe, startupProbe (dla wolno startujących). Load balancer: health check endpoint. Sprawdzaj: DB connection, disk space, key dependencies.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz environment variables w różnych środowiskach?', 'Per environment: .env.development, .env.staging, .env.production (NIE commituj .env z sekretami!). CI/CD: environment variables w pipeline (GitHub Secrets, GitLab CI Variables). Runtime: ConfigMap/Secret w K8s, Parameter Store (AWS). 12-factor: config w env vars. Walidacja: sprawdzaj wymagane zmienne na starcie (fail fast). dotenv w dev, native env vars w prod.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest semantic versioning (SemVer)?', 'SemVer: MAJOR.MINOR.PATCH — np. 2.1.3. MAJOR: breaking changes (niekompatybilne API). MINOR: nowe funkcje backward-compatible. PATCH: bug fix. Pre-release: 1.0.0-beta.1. Range w package.json: ^1.2.3 (minor+patch), ~1.2.3 (patch only). Lock file gwarantuje exact versions. 0.x.y: unstable, anything goes. Automatyzacja z conventional commits + semantic-release.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak konfigurujesz K8s pod z resource limits?', 'resources: requests (minimum gwarantowane — scheduler) i limits (maximum — OOM Kill jeśli przekroczy). CPU: requests: 100m (0.1 core), limits: 500m. Memory: requests: 128Mi, limits: 256Mi. QoS classes: Guaranteed (requests = limits), Burstable, BestEffort. Pod bez limits może zużyć cały node. LimitRange i ResourceQuota na namespace. Prawidłowe ustawienie wymaga profiling.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest container registry?', 'Container registry to repozytorium obrazów Docker. Docker Hub (publiczny), ECR (AWS), GCR (Google), GHCR (GitHub), Harbor (self-hosted). Workflow: build → tag (version + git SHA) → push → pull w deploy. Security: vulnerability scanning (Trivy, Snyk), signed images (cosign), least privilege (read-only w produkcji). Cache: pull-through cache zmniejsza latency i koszty.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest git worktree?', 'git worktree pozwala mieć wiele working directories z jednego repo. git worktree add ../hotfix main — nowy katalog z branchem main. Przydatne: praca na hotfix bez stashowania, porównanie branchy, długi build na jednym worktree, review PR w drugim. Współdzielą .git (oszczędność miejsca). git worktree list, remove. Alternatywa dla git stash przy częstym przełączaniu kontekstu.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak wdrażasz zero-downtime deployment w K8s?', 'Rolling update: K8s stopniowo zastępuje pody (maxSurge, maxUnavailable). Readiness probe zapewnia, że nowy pod jest gotowy przed usunięciem starego. Graceful shutdown: preStop hook + SIGTERM handling. PodDisruptionBudget gwarantuje minAvailable. Database: backward-compatible migrations. Health check endpoint. Alternatywa: canary z Argo Rollouts, blue-green z Service switch.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest DORA metrics?', 'DORA (DevOps Research and Assessment) — 4 metryki wydajności zespołu: 1) Deployment Frequency (jak często deploy), 2) Lead Time for Changes (commit → produkcja), 3) Change Failure Rate (% deployów powodujących incydent), 4) Time to Restore (MTTR — czas naprawy). Elite: deploy on demand, < 1h lead time, < 5% failure, < 1h restore. Mierzone narzędziami: Sleuth, LinearB, DORA dashboard.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak automatyzujesz security scanning w CI/CD?', 'SAST (Static Analysis): SonarQube, Semgrep — skanują kod. DAST (Dynamic): OWASP ZAP — skanują uruchomioną aplikację. Dependency scanning: npm audit, Snyk, Dependabot — znane CVE w zależnościach. Container scanning: Trivy, Grype — vulnerabilities w obrazach. Secret scanning: detect-secrets, GitGuardian. Integracja: GitHub Actions step, fail pipeline na critical. Shift-left security.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Jakie są semantyki metod HTTP i kiedy której używać?', 'GET: pobieranie (safe, idempotent, cacheable). POST: tworzenie zasobu (nie idempotent). PUT: pełna aktualizacja lub stworzenie (idempotent). PATCH: częściowa aktualizacja. DELETE: usunięcie (idempotent). HEAD: jak GET, ale bez body (sprawdzanie istnienia). OPTIONS: dostępne metody (CORS preflight). Safe = nie zmienia stanu, idempotent = wielokrotne wywołanie = ten sam efekt.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest idempotentność w kontekście HTTP?', 'Operacja idempotentna daje ten sam rezultat niezależnie od liczby wywołań. GET, PUT, DELETE, HEAD, OPTIONS są idempotentne. POST nie jest — każde wywołanie może tworzyć nowy zasób. Znaczenie: retry jest bezpieczny dla idempotentnych metod (network failure → retry bez duplikatów). PUT /users/1 wielokrotnie = ten sam efekt. POST /orders wielokrotnie = wiele zamówień.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij najważniejsze kody statusu HTTP z przykładami.', '200 OK, 201 Created (POST sukces), 204 No Content (DELETE sukces). 301 Moved Permanently, 304 Not Modified (cache). 400 Bad Request (walidacja), 401 Unauthorized (brak tokenu), 403 Forbidden (brak uprawnień), 404 Not Found, 409 Conflict (duplikat), 422 Unprocessable Entity, 429 Too Many Requests. 500 Internal Error, 502 Bad Gateway, 503 Service Unavailable.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są constraints REST wg Fieldinga?', 'Roy Fielding zdefiniował 6 ograniczeń: 1) Client-Server (separacja UI od danych), 2) Stateless (serwer nie przechowuje stanu sesji), 3) Cacheable (odpowiedzi oznaczone jako cacheable/not), 4) Uniform Interface (ujednolicony interfejs — URI, HTTP methods), 5) Layered System (klient nie wie, czy łączy się bezpośrednio czy przez proxy), 6) Code-On-Demand (opcjonalny, np. JS).', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest HATEOAS?', 'HATEOAS (Hypermedia As The Engine Of Application State) to constraint REST, w którym odpowiedź zawiera linki do powiązanych zasobów i akcji: {"id": 1, "_links": {"self": "/orders/1", "cancel": "/orders/1/cancel"}}. Klient nawiguje API przez linki, nie hardkodowane URL-e. W praktyce rzadko implementowane w pełni — większość API jest „RESTful" na poziomie 2 (Richardson Maturity Model).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są strategie wersjonowania API?', 'URI: /v1/users (najprostsze, explicit). Header: Accept: application/vnd.myapi.v2+json (czyste URL). Query: /users?version=2. Content negotiation: Accept header z media type. Najczęstsze: URI versioning. Zasady: minimum breaking changes, deprecation policy z sunset header, monitoruj użycie starych wersji, maintain max 2-3 wersje jednocześnie.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się cursor pagination od offset pagination?', 'Offset: ?page=5&limit=20 — OFFSET 80 LIMIT 20. Proste, pozwala skakać do strony, ale wolne dla dużych offsetów (skanuje wiersze) i niestabilne (nowe rekordy przesuwają strony). Cursor: ?after=abc123&limit=20 — WHERE id > cursor. Stała wydajność, stabilne wyniki, ale nie ma „skoku do strony 50". Cursor preferowany dla dużych zbiorów i infinite scroll.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementować rate limiting w API?', 'Algorytmy: token bucket (stały rate z burst), sliding window log, fixed window counter. Redis: INCR + EXPIRE lub sorted sets. Klucze: per user/API key, per IP, per endpoint. Response: 429 Too Many Requests + nagłówki X-RateLimit-Limit, X-RateLimit-Remaining, X-RateLimit-Reset, Retry-After. Tiery: free 100/h, paid 10000/h. API Gateway (Kong, AWS) ma built-in rate limiting.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa CORS i kiedy jest potrzebny?', 'CORS (Cross-Origin Resource Sharing) to mechanizm przeglądarki zezwalający na cross-origin requests. Serwer musi odpowiedzieć nagłówkami: Access-Control-Allow-Origin, Allow-Methods, Allow-Headers. Preflight (OPTIONS) wysyłany dla non-simple requests (custom headers, PUT/DELETE). Access-Control-Max-Age cache''uje preflight. Credentials: Allow-Credentials + explicit origin (nie *). Backend-to-backend nie podlega CORS.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się JWT od session-based authentication?', 'Session: serwer przechowuje sesję (w pamięci/Redis), klient dostaje session ID w cookie. Stateful — serwer wie o sesji. JWT: token zawiera dane (claims), podpisany — serwer weryfikuje podpis bez bazy. Stateless — łatwe skalowanie. JWT wady: nie da się unieważnić bez blacklisty, payload widoczny (base64), rozmiar. Session wady: wymaga shared storage w klasterze. Hybrid: krótki JWT + refresh token.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa OAuth 2.0?', 'OAuth 2.0 to framework autoryzacji (nie uwierzytelniania — to OIDC). Flow: 1) User redirectowany do Authorization Server, 2) loguje się i zatwierdza scope, 3) AS zwraca authorization code, 4) backend wymienia code na access token (+ refresh token). Granty: Authorization Code (web), PKCE (SPA/mobile), Client Credentials (server-to-server). Access token: krótki (15min), refresh token: długi + rotation.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się OAuth 2.0 od OpenID Connect?', 'OAuth 2.0 to framework autoryzacji — „co możesz zrobić" (access token). OpenID Connect (OIDC) to warstwa uwierzytelniania nad OAuth — „kim jesteś" (ID token z claims: sub, email, name). OIDC dodaje: ID token (JWT z identity), userinfo endpoint, standard scopes (openid, profile, email). Providery: Google, GitHub, Auth0, Keycloak. Używaj OIDC gdy potrzebujesz identity, OAuth gdy tylko dostęp.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zabezpieczasz API keys?', 'API key to prosty token identyfikujący klienta. Przekazywany w header (X-API-Key) lub query param (gorszy — logi). Zabezpieczenia: HTTPS (zawsze), hash w bazie (nie plain text), rate limiting per key, scoping (readonly vs write), rotation policy, expiration. Nie używaj API key jako jedynej autentykacji użytkowników — brak kontekstu „kto". Dla users: OAuth/JWT. API keys dla server-to-server.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest content negotiation?', 'Content negotiation to mechanizm, w którym klient i serwer uzgadniają format danych. Klient wysyła Accept: application/json (lub xml, csv). Serwer odpowiada Content-Type: application/json. Jeśli serwer nie obsługuje formatu: 406 Not Acceptable. Accept-Language dla lokalizacji. Accept-Encoding dla kompresji (gzip, br). W praktyce większość API obsługuje tylko JSON.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa cache HTTP (ETag, Cache-Control)?', 'Cache-Control: max-age=3600 (klient cache''uje 1h), no-cache (waliduj z serwerem), no-store (nie cache''uj). ETag: serwer zwraca hash contentu. Klient wysyła If-None-Match: etag — serwer odpowiada 304 Not Modified (nie przesyła body) lub 200 z nowym contentem. Last-Modified + If-Modified-Since analogicznie z datą. CDN cache''uje na krawędzi. Vary header: cache per Accept-Encoding/Language.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest OpenAPI/Swagger?', 'OpenAPI Specification (dawniej Swagger) to standard opisu REST API w YAML/JSON: endpointy, parametry, request/response schemas, autentykacja. Swagger UI generuje interaktywną dokumentację. Swagger Codegen generuje klienty i serwery. Design-first: napisz spec, potem implementuj. Code-first: generuj spec z kodu (annotacje). OpenAPI jest de facto standardem dokumentacji API.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest webhook i czym różni się od pollingu?', 'Polling: klient periodycznie odpytuje serwer „masz coś nowego?" — prosty, ale marnotrawny (puste odpowiedzi), opóźniony. Webhook: serwer wysyła HTTP POST do klienta gdy zdarzenie nastąpi — real-time, efektywny. Webhook wymaga: endpoint po stronie klienta, retry z backoff, signature verification, idempotency. Long polling i SSE to pośrednie rozwiązania. WebSocket dla bidirectional real-time.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektujesz error response w API?', 'Spójny format: { "error": { "code": "VALIDATION_ERROR", "message": "Email is required", "details": [...] } }. HTTP status code odpowiedni do typu błędu. Machine-readable code (enum) + human-readable message. Nie ujawniaj stack trace w produkcji. Walidacja: lista błędów per pole. RFC 7807 (Problem Details): standaryzowany format. Lokalizacja: Accept-Language dla message. Dokumentuj możliwe błędy per endpoint.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest REST maturity model (Richardson)?', 'Level 0: jeden endpoint, wszystko POST (SOAP-like). Level 1: zasoby z URI (/users, /orders), ale jeden method. Level 2: HTTP methods prawidłowo (GET, POST, PUT, DELETE) + status codes. Level 3: HATEOAS — hypermedia links w odpowiedziach. Większość „REST API" jest na Level 2. Level 3 jest rzadko implementowany w pełni. Prawdziwy REST wg Fieldinga wymaga Level 3.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektować URL-e w REST API?', 'Zasady: pluralne rzeczowniki (/users, /orders), hierarchia zasobów (/users/{id}/orders), HTTP methods zamiast akcji w URL (nie /getUser, ale GET /users/{id}). Filtrowanie: query params (?status=active&sort=name). Avoid: verbs w URL, zagnieżdżenie > 2 poziomy, camelCase (use kebab-case lub snake_case). Konsekwentnie w całym API. Wersja: /v1/users.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest GraphQL i jakie ma zalety/wady vs REST?', 'GraphQL: klient definiuje kształt odpowiedzi w query. Jeden endpoint. Zalety: brak over/under-fetching, typed schema, introspection, świetne tooling (GraphiQL, codegen). Wady: trudniejszy caching (POST, dynamic shapes), complexity (N+1 bez DataLoader), file upload problematic, learning curve. REST: prostszy, lepszy HTTP caching, dojrzalszy ekosystem. GraphQL sprawdza się gdy masz wiele klientów z różnymi potrzebami.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest gRPC i kiedy go wybrać zamiast REST?', 'gRPC to framework RPC od Google używający Protocol Buffers (binary serialization) i HTTP/2. Zalety: szybki (binary, multiplexing), typed contracts (.proto), streaming (uni/bi-directional), code generation. Wady: nie human-readable, trudny w przeglądarce (grpc-web), mniej tooling. Kiedy: microservice-to-microservice (internal), high-performance, streaming. REST dla public API, gRPC wewnętrznie.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsłużyć bulk operations w REST API?', 'Opcje: 1) POST /users/bulk z tablicą obiektów — prosty, ale atomowy (all or nothing). 2) Batch endpoint: POST /batch z tablicą requestów. 3) Async: POST /jobs zwraca job ID, GET /jobs/{id} sprawdza status. Odpowiedzi: 200 z partial success (tablica wyników per item) lub 207 Multi-Status. Idempotency key per item. Limit batch size. Async dla długich operacji.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest HTTP/2 i jakie ma zalety?', 'HTTP/2: binary framing (szybsze parsowanie), multiplexing (wiele requestów na jednym połączeniu — brak head-of-line blocking na level HTTP), header compression (HPACK), server push (preemptive wysyłanie zasobów). Zalety: szybsze ładowanie stron, mniej połączeń TCP. Wymaga HTTPS (w praktyce). HTTP/3 (QUIC): UDP zamiast TCP, eliminuje HOL blocking na transport level.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz filtrowanie, sortowanie i projekcję w API?', 'Filtrowanie: query params — ?status=active&role=admin, zaawansowane: ?filter[age][gte]=18. Sortowanie: ?sort=name,-created_at (- = desc). Projekcja: ?fields=id,name,email (zwróć tylko te pola). Paginacja: ?page=2&limit=20 lub ?after=cursor. Standardy: JSON:API, OData. Waliduj i whitelist dozwolone pola (security). Nie pozwalaj na sort po nieindeksowanych kolumnach.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest idempotency key i jak go używać?', 'Idempotency key to unikalny identyfikator (UUID) wysyłany w header (Idempotency-Key) przez klienta. Serwer zapamiętuje wynik dla danego klucza — kolejne requesty zwracają cached response. Kluczowe dla: płatności (unikaj podwójnych charge), POST (nieidempotentny). Implementacja: Redis z TTL, check before processing. Stripe, AWS, PayPal używają tego wzorca.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Server-Sent Events (SSE)?', 'SSE to jednokierunkowy streaming od serwera do klienta przez HTTP. Content-Type: text/event-stream. Format: data: message\\n\\n. EventSource API w przeglądarce: auto-reconnect, last-event-id. Zastosowania: notyfikacje, live feed, dashboardy. Prostrzy niż WebSocket (HTTP, auto-reconnect, compatible z proxy/LB). Wada: jednokierunkowy, text only. WebSocket lepszy dla bidirectional (chat, gaming).', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz long-running operations w API?', 'Wzorzec async: POST /exports → 202 Accepted + Location: /jobs/123. GET /jobs/123 → { "status": "processing" } lub { "status": "completed", "result_url": "..." }. Polling lub webhook notification po zakończeniu. Timeout: nigdy nie trzymaj HTTP connection minutami. Queue + worker przetwarza w tle. Retry z idempotency. Status tracking: pending → processing → completed/failed.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest API Gateway i jakie ma funkcje?', 'API Gateway to single entry point dla klientów. Funkcje: routing (URL → microservice), autentykacja/autoryzacja, rate limiting, request/response transformation, caching, logging, circuit breaker, SSL termination. Narzędzia: Kong, AWS API Gateway, Nginx, Traefik. BFF pattern: osobny gateway per klient (web, mobile). Uwaga: single point of failure — wymaga HA setup.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak wersjonujesz zmiany w API bez łamania klientów?', 'Backward-compatible changes (nie wymagają nowej wersji): dodanie opcjonalnego pola, dodanie endpointu, dodanie enum value (jeśli klient ignoruje unknown). Breaking changes (wymagają nowej wersji): usunięcie/zmiana pola, zmiana typu, zmiana semantyki. Strategia: additive changes, deprecation z Sunset header, monitoring usage starych pól/endpointów, minimum 6 miesięcy na migrację.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest request validation i jak ją implementować?', 'Walidacja requestu: sprawdzanie danych wejściowych przed przetworzeniem. Warstwy: 1) Schema validation (Zod, Joi, class-validator) — typy, format, range. 2) Business validation — logika biznesowa. Odpowiedź: 400/422 z listą błędów per pole. Waliduj: body, query params, path params, headers. Fail fast — nie przetwarzaj nieprawidłowych danych. Server-side walidacja jest obowiązkowa (klient jest niezaufany).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest HTTPS i jak działa TLS handshake?', 'HTTPS = HTTP + TLS (Transport Layer Security). Handshake: 1) Client Hello (supported ciphers), 2) Server Hello (chosen cipher + certificate), 3) Klient weryfikuje certyfikat (CA chain), 4) Key exchange (asymmetric → symmetric key), 5) Szyfrowana komunikacja (symmetric). TLS 1.3: szybszy (1-RTT, 0-RTT resume). Let''s Encrypt: darmowe certyfikaty z auto-renewal. HSTS header wymusza HTTPS.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektować sub-resources w REST?', 'Sub-resources to zasoby zagnieżdżone: /users/{userId}/orders — zamówienia danego usera. GET /users/1/orders — lista, POST /users/1/orders — stwórz. Ale: GET /orders/123 (nie /users/1/orders/123) jeśli order ma global ID. Zasada: max 2 poziomy zagnieżdżenia. Jeśli sub-resource ma sens niezależnie — daj mu top-level endpoint. Alternatively: filter ?userId=1 na /orders.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest PATCH i czym różni się od PUT?', 'PUT zastępuje cały zasób — musisz wysłać kompletny obiekt. PATCH modyfikuje częściowo — wysyłasz tylko zmieniane pola. PUT jest idempotentny (ten sam request = ten sam stan). PATCH formalnie nie musi być idempotentny (JSON Patch: operacje add/remove). W praktyce: JSON Merge Patch (wysyłasz { "name": "Jan" }) jest najprostszy i najczęstszy. Używaj PATCH dla update formularzy.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak logować requesty API bezpiecznie?', 'Loguj: method, URL, status code, response time, request ID, user ID. NIE loguj: passwords, tokens, full credit card, PII (RODO). Maskowanie: Authorization header → "Bearer ***", body fields → sanitize. Structured logging (JSON): łatwiejszy parsing. Correlation ID: generuj w API Gateway, przekazuj przez serwisy. Request ID w response header (X-Request-ID) — debugging z klientem.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest WebSocket i kiedy go używać?', 'WebSocket to protokół bidirectional, full-duplex na jednym TCP połączeniu. Handshake: HTTP upgrade → ws://. Zastosowania: chat, gaming, collaborative editing, live data (trading). Zalety: real-time, low latency, oba kierunki. Wady: trudniejsze skalowanie (sticky sessions/Redis pub-sub), reconnect logic, firewall issues. Alternatywy: SSE (one-way), long polling (prostsze). Socket.io opakowuje z fallback.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz file upload w API?', 'Multipart: POST z Content-Type: multipart/form-data — klasyczne, limit rozmiaru. Base64 w JSON: proste, ale 33% overhead. Signed URL: klient dostaje presigned URL (S3), uploaduje bezpośrednio do storage — serwer nie jest bottleneckiem. Chunked upload: resumable, duże pliki (tus protocol). Walidacja: typ pliku (magic bytes, nie tylko extension), rozmiar, virus scan. Storage: S3, GCS, nie filesystem serwera.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest circuit breaker w kontekście API?', 'Circuit breaker chroni klienta przed ciągłym wysyłaniem requestów do nieosiągalnego serwisu. Stany: Closed (normalny flow), Open (po X błędach — natychmiastowy fallback, bez wysyłania), Half-Open (po timeout próbuje — sukces = Closed, błąd = Open). Implementacja: interceptor/middleware. Fallback: cached data, default response, graceful degradation message. Axios + custom logic lub dedykowana biblioteka.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak testować REST API?', 'Unit: testuj handlery/kontrolery z mockowanymi serwisami. Integration: supertest/httptest — prawdziwe HTTP requesty do serwera in-memory + testowa baza. Contract: Pact — weryfikacja zgodności klient-serwer. E2E: Postman/Newman, REST Client. Testuj: happy path, walidacja (400), auth (401/403), not found (404), edge cases. CI: automatyczne testy API w pipeline. Collection testing: Postman z env variables.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest ETL vs API w kontekście integracji systemów?', 'API (real-time): synchroniczne zapytania, aktualne dane, niski latency. ETL (Extract, Transform, Load — batch): periodyczne kopiowanie danych między systemami, transformacja po drodze. API lepsze dla: user-facing operations, real-time needs. ETL lepsze dla: analytics, data warehouse, duże wolumeny, systemy bez API. Hybrid: CDC (Change Data Capture) — real-time streaming zmian z bazy do innego systemu.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
